_SELF_HOST_DRIVER_CACHE = {}  # driver-source-hash -> (driver_wsl, in_path, out_path)


def _compile_src_to_elf(src: str, optimize: bool = True) -> bytes:
    """compile_and_run's pipeline, but return the ELF bytes WITHOUT running."""
    prog = parse(src, include_stdlib=True)
    flatten_modules(prog)
    flatten_impls(prog)
    monomorphize(prog)
    grad_pass(prog)
    mod = lower(prog)
    from helixc.backend.ptx import validate_kernel_tile_lowering
    validate_kernel_tile_lowering(mod)
    if optimize:
        fold_module(mod)
        cse_module(mod)
        dce_module(mod)
        fdce_module(mod)
    return compile_module_to_elf(mod)


def _self_host_driver():
    """PERF (2026-05-28): build the K1 self-host driver ELF ONCE per session
    (per bootstrap-source hash) and reuse it for every k2_src in a run -- the
    Python-compile of the ~thousands-line lexer+parser+kovc driver dominated
    self-host test time (~13s/test). Returns (driver_wsl, in_path, out_path).

    The driver reads a FIXED per-worker in_path and writes a FIXED out_path, so
    the SAME ELF compiles every program. Cache key is the hash of the full driver
    source, so ANY edit to lexer/parser/kovc.hx rebuilds it (correctness). Paths
    are namespaced by PYTEST_XDIST_WORKER so parallel workers don't collide."""
    worker = os.environ.get("PYTEST_XDIST_WORKER", "main")
    in_path = f"/tmp/sh_drv_{worker}_in.hx"
    out_path = f"/tmp/sh_drv_{worker}_out.bin"
    proj = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
    lexer = open(os.path.join(proj, "helixc", "bootstrap", "lexer.hx")).read()
    lexer_no_main = lexer.rsplit(
        "// --------------------------------------------------------------\n// Demo:", 1)[0]
    parser_body = open(os.path.join(proj, "helixc", "bootstrap", "parser.hx")).read()
    kovc = open(os.path.join(proj, "helixc", "bootstrap", "kovc.hx")).read()
    kovc_lib = kovc.rsplit(
        "// --------------------------------------------------------------\n// Demo:", 1)[0]
    k1_main = f"""
fn main() -> i32 {{
    let src_start = __arena_len();
    let src_len = read_file_to_arena("{in_path}");
    let tok_base = __arena_len();
    lex(src_start, src_len);
    let ast_root = parse_top(tok_base);
    let total = emit_elf_for_ast_to_path(ast_root);
    let elf_start = __arena_len() - total;
    write_file_to_arena("{out_path}", elf_start, total)
}}
"""
    driver_src = lexer_no_main + parser_body + kovc_lib + k1_main
    import hashlib
    h = hashlib.sha256(driver_src.encode("utf-8")).hexdigest()[:16]
    cached = _SELF_HOST_DRIVER_CACHE.get(h)
    if cached is None:
        elf = _compile_src_to_elf(driver_src)
        out_dir = os.path.join(proj, "helixc", "tests", "_tmp")
        os.makedirs(out_dir, exist_ok=True)
        drv_path = os.path.join(out_dir, f"sh_driver_{worker}_{h}.bin")
        with open(drv_path, "wb") as f:
            f.write(elf)
        os.chmod(drv_path, 0o755)
        cached = (_win_to_wsl(drv_path), in_path, out_path)
        _SELF_HOST_DRIVER_CACHE[h] = cached
    return cached


def _kovc_self_host_compile_and_run(name: str, k2_src: str) -> int:
    """K1.F-discovery test helper (2026-05-25): compile `k2_src` via the full
    P0 -> K1 -> K2 bootstrap chain and return the K2 exit code.

    PERF (2026-05-28): the K1 driver (Python-compiled lexer+parser+kovc) is now
    built once per session via _self_host_driver() and reused (cache keyed on the
    bootstrap-source hash), instead of recompiling the ~thousands-line driver on
    every call. `name` is retained for signature/log compatibility but no longer
    namespaces the /tmp paths (the driver uses fixed per-worker paths; pytest runs
    tests sequentially within a worker, so there is no collision).
    """
    import subprocess
    driver_wsl, in_path, out_path = _self_host_driver()
    # Write k2_src to the (fixed, per-worker) in_path and clear any stale
    # out_path. cat-via-stdin preserves all bytes incl. newlines -- K1.F24i: the
    # old `printf %s` form corrupted multi-line sources into one line with
    # literal `\n`, which lexed wrong and SIGILL'd (a helper bug, not codegen).
    subprocess.run(
        ["wsl", "-e", "bash", "-c",
         f"rm -f {in_path} {out_path} && cat > {in_path}"],
        input=k2_src.encode("utf-8"),
        check=True, timeout=10,
    )
    # Run the CACHED driver ELF: it lexes+parses+emit_elf in_path -> out_path.
    # (Was: recompile the whole lexer+parser+kovc driver via compile_and_run on
    # every call -- now built once per source-hash in _self_host_driver().)
    subprocess.run(
        ["wsl", "-e", "bash", "-c",
         f"chmod +x {driver_wsl} && {driver_wsl}"],
        timeout=30,
    )
    run_k2 = subprocess.run(
        ["wsl", "-e", "bash", "-c",
         f"chmod +x {out_path} && {out_path}"],
        capture_output=True, timeout=10,
    )
    return run_k2.returncode


def test_bootstrap_self_host_lexer_hx():
    """PHASE C / C1 (2026-05-28): SELF-HOST FIXPOINT -- leg 1 (lexer.hx).

    The bootstrap kovc (itself built by Python helixc) compiles its OWN
    lexer.hx source -- 1029 lines / ~43.7 KB -- all the way through:
    lex + parse + emit_elf succeed, producing a ~20 KB ELF, and the
    emitted binary's Demo main exits with the SAME code as the
    Python-compiled lexer.hx. i.e. the self-hosted bootstrap compiles
    its smallest own source file with byte-behavior PARITY to the
    Python reference -- the first leg of the K2 Phase-3 fixpoint
    (kovc compiling kovc). No cap overflow, no unsupported construct.

    Legs 2 (parser.hx) and 3 (kovc.hx) are larger and may hit fixed
    caps; this pins that leg 1 is clean.
    """
    import os
    proj = os.path.dirname(os.path.dirname(os.path.dirname(
        os.path.abspath(__file__))))
    lexer = open(os.path.join(
        proj, "helixc", "bootstrap", "lexer.hx")).read()
    py_rc = compile_and_run(lexer)
    boot_rc = _kovc_self_host_compile_and_run("c1_selfhost_lexer", lexer)
    assert boot_rc == py_rc, (
        f"self-host lexer.hx: bootstrap-compiled rc={boot_rc} != "
        f"Python-compiled rc={py_rc} -- a self-host codegen divergence."
    )


def test_bootstrap_fn_type_table_over_256():
    """Safe-hardening (2026-05-28): fn_type_table cap 256 -> 1024. A program
    with more than 256 fns used to silently drop type-table entries past
    #256, so a non-i32-return fn beyond #256 mis-typed at its call site --
    here an f32-returning fn (the 281st) read as i32, which SIGILL'd (132).
    With the bumped cap its f32 return type is recorded and the program runs
    correctly (42). The bootstrap now handles realistic multi-hundred-fn
    programs (the full self-host driver has 673 fns). This is also a
    prerequisite for the parser.hx/kovc.hx self-host fixpoint legs."""
    fillers = "".join("fn g%d() -> i32 { 0 } " % i for i in range(280))
    src = (fillers +
           "fn getf() -> f32 { 2.0 } "
           "fn main() -> i32 { let x: f32 = getf(); if x > 1.0 { 42 } else { 0 } }")
    rc = _kovc_self_host_compile_and_run("fn_type_table_over_256", src)
    assert rc == 42, (
        f"fn_type_table >256 fns: bootstrap rc={rc}, expected 42 "
        f"(pre-fix this was 132 -- the 256-cap dropped the f32 fn's type)"
    )


def test_bootstrap_array_indexed_store():
    """S3 audit fix (2026-05-28): array indexed-store `a[i] = v` on the
    CPU/ELF path. emit_ast_code had no AST_INDEX_STORE (tag 55) arm on the
    CPU path (only the PTX/WGSL emitters did), so `a[i] = v` fell through to
    the unhandled-tag trap -> SIGILL (132), even for a CONSTANT index. Python
    helixc compiled it correctly, so this was a real both-compiler divergence
    surfaced by the S3 dry-run audit. Now fixed via emit_index_store_cpu
    (element addr = base + index*8, 4-byte store, mirroring the tag-53 read).
    Covers constant index, variable index, and loop fill+sum."""
    cases = [
        ("const", "fn main() -> i32 { let mut a = [1,2,3]; a[0] = 42; a[0] }", 42),
        ("var",   "fn main() -> i32 { let mut a = [1,2,3]; let i = 0; a[i] = 42; a[i] }", 42),
        ("loop",  "fn main() -> i32 { let mut a = [0,0,0]; let mut i = 0; while i < 3 { a[i] = 14; i = i + 1; } a[0]+a[1]+a[2] }", 42),
    ]
    for name, src, exp in cases:
        rc = _kovc_self_host_compile_and_run(f"arr_store_{name}", src)
        assert rc == exp, (
            f"array indexed-store {name}: bootstrap rc={rc}, expected {exp} "
            f"(pre-fix this SIGILL'd at 132 -- no CPU AST_INDEX_STORE arm)"
        )


def test_bootstrap_struct_field_store_self_host():
    """S3 audit finding (2026-05-28): the bootstrap EXCEEDS Python on
    struct field STORE. `let mut p = P{x:0}; p.x = 42; p.x` correctly
    returns 42 in the bootstrap, but Python helixc returns 0 -- it does
    NOT persist the field write (a real Python-side bug; the two-field
    case `p.x=40; p.y=2; p.x+p.y` gives 40 in Python vs the correct 42 in
    the bootstrap). This is the 6th 'bootstrap is more correct than
    Python' case (after generics/fn-ptr/tuple/closure/GPU): deletion-
    favorable -- deleting the buggy Python loses nothing. Bootstrap-only
    pin (not K2-parity-able, since py != kc and py is the wrong one).
    NOTE: we do NOT fix Python (K4 deletes it); we pin that the bootstrap
    is correct."""
    cases = [
        ("one_field", "struct P { x:i32 } fn main() -> i32 { let mut p = P{x:0}; p.x = 42; p.x }", 42),
        ("two_field", "struct P { x:i32, y:i32 } fn main() -> i32 { let mut p = P{x:40,y:0}; p.y = 2; p.x + p.y }", 42),
        ("in_loop",   "struct P { x:i32 } fn main() -> i32 { let mut p = P{x:0}; let mut i = 0; while i < 6 { p.x = p.x + 7; i = i + 1; } p.x }", 42),
        # S3 struct-memory audit (2026-05-28): NESTED field store `o.i.v = v`
        # deepens the same Python bug -- Python returns 0 (no persist), the
        # bootstrap correctly returns 42. (Reads `o.i.v` without a store work in
        # BOTH -- pinned as K2 p277/p278; only the nested STORE diverges.)
        ("nested_store", "struct Inner { v: i32 } struct Outer { i: Inner } fn main() -> i32 { let mut o = Outer { i: Inner { v: 0 } }; o.i.v = 42; o.i.v }", 42),
    ]
    for name, src, exp in cases:
        rc = _kovc_self_host_compile_and_run(f"sfs_{name}", src)
        assert rc == exp, (
            f"struct field store {name}: bootstrap rc={rc}, expected {exp} "
            f"(bootstrap is correct here; Python helixc has the bug)"
        )


def test_bootstrap_parser_exceeds_python_self_host():
    """S3 parser audit (2026-05-28): two more bootstrap-exceeds-Python parser
    cases (deletion-favorable). (1) Extra/empty statements `let x = 42;; x`:
    the bootstrap accepts the doubled `;` and returns 42; Python helixc
    ParseErrors. (2) Char literals `let c = 'A'; 42`: the bootstrap parses
    the char literal and returns 42; Python helixc NotImplementedErrors.
    Both are bootstrap-only pins (not K2-parity-able since Python errors).
    The bootstrap's front-end is strictly more permissive/capable here."""
    cases = [
        ("extra_semis", "fn main() -> i32 { let x = 42;; x }", 42),
        ("char_lit",    "fn main() -> i32 { let c = 'A'; 42 }", 42),
    ]
    for name, src, exp in cases:
        rc = _kovc_self_host_compile_and_run(f"px_{name}", src)
        assert rc == exp, (
            f"parser-exceeds-python {name}: bootstrap rc={rc}, expected {exp}"
        )


def test_bootstrap_generics_exceed_python_self_host():
    """S3 generics audit (2026-05-28): GENERICS are a broad bootstrap-exceeds-
    Python axis. Python helixc ParseErrors on ALL generic syntax -- `struct
    Box<T>`, `fn id<T>`, `enum Opt<T>`, `impl<T>` -- it has no generics at all.
    The bootstrap compiles them correctly. This is strongly deletion-favorable:
    deleting Python loses generics it never had. Bootstrap-only pins (not
    K2-parity-able, since the Python path can't parse the source).

    KNOWN LIMITATION (deferred, NOT a regression): a generic field whose type is
    ITSELF a generic instantiation -- `struct Box<T>{v:T}; let b = Box{v: Box{v:
    42}}; b.v.v` -- stably SIGILLs (rc 132). The non-generic equivalent
    (`Outer{Inner{v}}.i.v`) works (rc 42). Root cause is the Stage 28.11 INC-3a
    marker (parser.hx ~2679): a generic-param-typed field carries `200+gp_idx`
    and is treated as SCALAR (4-byte) pending the INC-3b use-site
    monomorphization, so the nested `.v.v` mis-reads. This is a documented
    multi-step feature gap (INC-3b), beyond Python's capability either way --
    flagged for an attended fix, not chased unattended here."""
    works = [
        ("box_single", "struct Box<T> { v: T } fn main() -> i32 { let b = Box { v: 42 }; b.v }", 42),
        ("box_two",    "struct Box<T> { v: T } fn main() -> i32 { let a = Box { v: 40 }; let b = Box { v: 2 }; a.v + b.v }", 42),
        ("pair2",      "struct Pair<A, B> { a: A, b: B } fn main() -> i32 { let p = Pair { a: 40, b: 2 }; p.a + p.b }", 42),
        ("pair_swap",  "struct Pair<A, B> { a: A, b: B } fn main() -> i32 { let p = Pair { a: 2, b: 40 }; p.b + p.a }", 42),
        ("fn_id",      "fn id<T>(x: T) -> T { x } fn main() -> i32 { id(40) + id(2) }", 42),
        ("struct_arg", "struct Box<T> { v: T } fn unwrap(b: Box<i32>) -> i32 { b.v } fn main() -> i32 { unwrap(Box { v: 42 }) }", 42),
        ("gen_enum",   "enum Opt<T> { Some(T), None } fn main() -> i32 { let o = Opt::Some(42); match o { Opt::Some(x) => x, Opt::None => 0 } }", 42),
        ("gen_method", "struct Box<T> { v: T } impl<T> Box<T> { fn get(self) -> T { self.v } } fn main() -> i32 { let b = Box { v: 42 }; b.get() }", 42),
        ("box_mut",    "struct Box<T> { v: T } fn main() -> i32 { let mut b = Box { v: 0 }; b.v = 42; b.v }", 42),
    ]
    # retry-on-132: the self-host harness has a known intermittent WSL SIGILL
    # (rc 132) on tiny programs; none of these shapes legitimately return 132
    # (all expect 42), so retrying only on 132 absorbs the env flake without
    # masking a real failure (a real one is a stable wrong VALUE).
    for name, src, exp in works:
        rc = _kovc_self_host_compile_and_run(f"genx_{name}", src)
        tries = 0
        while rc == 132 and rc != exp and tries < 2:
            tries = tries + 1
            rc = _kovc_self_host_compile_and_run(f"genx_{name}_r{tries}", src)
        assert rc == exp, (
            f"generics-exceed-python {name}: bootstrap rc={rc}, expected {exp} "
            f"(Python helixc ParseErrors on this generic syntax)"
        )


def test_bootstrap_enum_payload_param_self_host():
    """S3 enum audit fix (2026-05-28): an enum with a PAYLOAD-carrying variant,
    passed BY VALUE as a function parameter, SIGILL'd (132) -- even when the body
    ignored the param. A payload enum value is an 8-byte pointer (a tag-50 tuple
    [disc, payload...]), but parse_fn_decl only recognized struct/generic param
    types, so an enum param defaulted to i32 (p_ty 0); at the call site the
    8-byte tuple-lit arg (expr_type 3) mismatched the i32 param -> the 16001
    arg-type trap -> ud2 (before the body even ran). Fixed by encoding enum-with-
    payload params with the same 100+idx pointer sentinel as struct params
    (parser.hx parse_fn_decl), routing them through the existing 8-byte prologue
    store + call-site struct-exemption + match pointer-deref path. Python helixc
    handled these all along -> real bootstrap-only divergence, now parity (also
    pinned in K2 p281-p285). Nullary-only enum params were unaffected (stay
    i32-disc). retry-on-132 absorbs the WSL self-host flake."""
    cases = [
        ("match_V",      "enum E { Z, V(i32) } fn f(e: E) -> i32 { match e { E::Z => 0, E::V(x) => x } } fn main() -> i32 { f(E::V(42)) }", 42),
        ("match_Z",      "enum E { Z, V(i32) } fn f(e: E) -> i32 { match e { E::Z => 42, E::V(x) => x } } fn main() -> i32 { f(E::Z) }", 42),
        ("body_ignores", "enum E { Z, V(i32) } fn f(e: E) -> i32 { 42 } fn main() -> i32 { f(E::V(7)) }", 42),
        ("multi_payload","enum E { P(i32, i32) } fn f(e: E) -> i32 { match e { E::P(a, b) => a + b } } fn main() -> i32 { f(E::P(40, 2)) }", 42),
        ("order_swap",   "enum E { V(i32), Z } fn f(e: E) -> i32 { match e { E::V(x) => x, E::Z => 0 } } fn main() -> i32 { f(E::V(42)) }", 42),
        ("nullary_ok",   "enum E { A, B } fn f(e: E) -> i32 { match e { E::A => 42, E::B => 0 } } fn main() -> i32 { f(E::A) }", 42),
    ]
    for name, src, exp in cases:
        rc = _kovc_self_host_compile_and_run(f"enp_{name}", src)
        tries = 0
        while rc == 132 and rc != exp and tries < 2:
            tries = tries + 1
            rc = _kovc_self_host_compile_and_run(f"enp_{name}_r{tries}", src)
        assert rc == exp, (
            f"enum-payload-param {name}: bootstrap rc={rc}, expected {exp} "
            f"(pre-fix this SIGILL'd 132 -- enum-with-payload fn param mis-sized as i32)"
        )


def test_bootstrap_if_not_paren_self_host():
    """S3 audit fix (2026-05-28): `if !(<expr>) { .. } else { .. }` always took
    the THEN-branch in the bootstrap (real both-compiler divergence: Python
    helixc was correct). ROOT CAUSE: the macro-call detector in parse_primary
    (`IDENT ! (`/`[`/`{` -> macro invocation) fired on KEYWORD-leading shapes.
    `if`, `while`, `match`, `return` etc. are lexed as TK_IDENT (the parser
    dispatches by name), so `if !(b) {..}` was mis-read as a macro `if!(...)`,
    the macro handler consumed the keyword + `!(...)`, and the real control-
    flow statement was destroyed. FIX: guard is_macro_call so it does not fire
    when the leading IDENT is a reserved keyword (no real macro is keyword-
    named). Covers if / while / return / match cond positions, bare-`!` and
    paren-`!` operands, plus a real `println!` macro to confirm the guard did
    NOT break legitimate macro detection."""
    cases = [
        # the bug: paren operand in if-cond
        ("if_b1",     "fn main() -> i32 { let b = 1; if !(b) { 7 } else { 9 } }", 9),
        ("if_b0",     "fn main() -> i32 { let b = 0; if !(b) { 7 } else { 9 } }", 7),
        ("if_eqeq",   "fn main() -> i32 { if !(5 == 5) { 7 } else { 9 } }", 9),
        ("if_notnot", "fn main() -> i32 { let b = 1; if !(!b) { 7 } else { 9 } }", 7),
        ("if_sum",    "fn main() -> i32 { let b = 1; if !(b + 0) { 7 } else { 9 } }", 9),
        # while-cond and return positions share the keyword-prefix shape
        ("while",     "fn main() -> i32 { let mut b = 0; let mut n = 0; while !(b) { n = n + 1; b = 1; } n }", 1),
        ("return",    "fn neg(x: i32) -> i32 { return !(x); } fn main() -> i32 { neg(0) + neg(5) }", 1),
        ("match",     "fn main() -> i32 { match !(0) { 1 => 42, _ => 0 } }", 42),
        # bare-`!` and outer-paren forms must keep working (no regression)
        ("bare",      "fn main() -> i32 { let b = 1; if !b { 7 } else { 9 } }", 9),
        ("wrapped",   "fn main() -> i32 { let b = 1; if (!(b)) { 7 } else { 9 } }", 9),
        # the guard must NOT break a real (non-keyword) macro
        ("real_macro","fn main() -> i32 { println!(\"hi\"); 42 }", 42),
    ]
    # The self-host harness has a known intermittent WSL SIGILL (rc 132) on
    # tiny programs (unrelated to codegen correctness; see the impl_method
    # flake note). Retry ONLY on rc==132: a real mis-branch produces a stable
    # WRONG VALUE (e.g. 7 instead of 9), never a random 132, so the retry
    # absorbs the env flake without masking a genuine regression (a persistent
    # 132 still fails after the retries).
    for name, src, exp in cases:
        rc = _kovc_self_host_compile_and_run(f"ifnotparen_{name}", src)
        tries = 0
        while rc == 132 and rc != exp and tries < 2:
            tries = tries + 1
            rc = _kovc_self_host_compile_and_run(f"ifnotparen_{name}_r{tries}", src)
        assert rc == exp, (
            f"if-!(paren) {name}: bootstrap rc={rc}, expected {exp} "
            f"(pre-fix the keyword-prefixed `!(` mis-fired as a macro call)"
        )


def _kovc_self_host_emit_ptx(name: str, k2_src: str,
                             emit_fn: str = "emit_ptx_for_ast_to_path") -> bytes:
    """K1.M1 (2026-05-27): DIRECT-TO-GPU emission harness. Compiles
    `k2_src` through the P0 -> K1 bootstrap chain, but instead of
    emit_elf_for_ast_to_path (x86_64 ELF binary) it invokes the new
    emit_ptx_for_ast_to_path -- emitting NVIDIA PTX *text* for any
    @kernel fn. Returns the emitted /tmp/sh_<name>_out.ptx bytes.

    The output is PTX text, not an x86 binary, so (unlike
    _kovc_self_host_compile_and_run) we do NOT chmod+x / run it -- we
    `cat` it and shape-check the text. ptxas round-trip validation is
    a later chunk; Python's helixc/backend/ptx.py uses the same
    text-shape-check fallback when ptxas is unavailable. Direct
    tile-IR -> PTX, NO MLIR (docs/MLIR_NOT_NEEDED_DECISION.md).
    """
    import os, subprocess
    proj = os.path.dirname(os.path.dirname(os.path.dirname(
        os.path.abspath(__file__))))
    lexer = open(os.path.join(
        proj, "helixc", "bootstrap", "lexer.hx")).read()
    lexer_no_main = lexer.rsplit(
        "// --------------------------------------------------------------\n// Demo:",
        1,
    )[0]
    parser_body = open(os.path.join(
        proj, "helixc", "bootstrap", "parser.hx")).read()
    kovc = open(os.path.join(
        proj, "helixc", "bootstrap", "kovc.hx")).read()
    kovc_lib = kovc.rsplit(
        "// --------------------------------------------------------------\n// Demo:",
        1,
    )[0]
    in_path = f"/tmp/sh_{name}_in.hx"
    out_path = f"/tmp/sh_{name}_out.ptx"
    k1_main = f"""
fn main() -> i32 {{
    let src_start = __arena_len();
    let src_len = read_file_to_arena("{in_path}");
    let tok_base = __arena_len();
    lex(src_start, src_len);
    let ast_root = parse_top(tok_base);
    let total = {emit_fn}(ast_root);
    let ptx_start = __arena_len() - total;
    write_file_to_arena("{out_path}", ptx_start, total)
}}
"""
    subprocess.run(
        ["wsl", "-e", "bash", "-c",
         f"rm -f {in_path} {out_path} && cat > {in_path}"],
        input=k2_src.encode("utf-8"),
        check=True, timeout=10,
    )
    compile_and_run(lexer_no_main + parser_body + kovc_lib + k1_main)
    out = subprocess.run(
        ["wsl", "-e", "bash", "-c", f"cat {out_path}"],
        capture_output=True, timeout=10,
    )
    return out.stdout


# K1.M5a (2026-05-28): shared PTX golden fragments. The bootstrap
# emitter byte-matches Python ptx.py for these pieces, so the tests
# build expected output from the same building blocks (header + per-
# entry signature + register-file decls + ret).
_PTX_HEADER = (
    b".version 8.0\n"
    b".target sm_75\n"
    b".address_size 64\n"
    b"\n"
)
_PTX_REG_BLOCK = (
    b"    .reg .pred  %p<256>;\n"
    b"    .reg .b32   %r<256>;\n"
    b"    .reg .b64   %rd<256>;\n"
    b"    .reg .f32   %f<256>;\n"
    b"    .reg .b16   %h<256>;\n"
    b"\n"
)


def _ptx_entry(sig: bytes, movs=(0,)) -> bytes:
    """One PTX .entry block: signature + register-file decls + one
    SCALAR_CONST_INT `mov.s32 %r<i>, <const>;` per entry in `movs`
    (positional registers %r0, %r1, ...) + ret. `movs` defaults to
    (0,) -- the `{ 0 }` body of the M1-M4 fixtures, which lowers to
    `mov.s32 %r0, 0;`. K1.M5c walks an AST_LET chain, so a body with N
    const-init lets yields N movs (%r0..%r(N-1))."""
    body = b""
    for i, c in enumerate(movs):
        body += (b"    mov.s32 %r" + str(i).encode()
                 + b", " + str(c).encode() + b";\n")
    return (
        b".visible .entry " + sig + b"\n"
        b"{\n"
        + _PTX_REG_BLOCK
        + body
        + b"    ret;\n"
        b"}\n"
    )


def test_bootstrap_ptx_empty_kernel():
    """K1.M1 (2026-05-27): FIRST direct-to-GPU (NVIDIA PTX) emission.
    A @kernel fn drives the bootstrap to emit a minimal valid PTX
    module (text), exactly as a normal fn drives x86_64 ELF emission.
    Direct tile-IR -> PTX text, NO MLIR (docs/MLIR_NOT_NEEDED_DECISION
    .md -- ratified + verified; docs/GPU_DIRECT_EMIT_PLAN.md).

    Proves the full GPU pipeline end to end: parse(@kernel) ->
    detect(is_kernel AST slot 14) -> emit PTX bytes -> write .ptx ->
    shape-check text. This is the GPU analog of the bootstrap's first
    ELF test. Phase-0 narrowing: entry name hardcoded 'k'; the kernel
    body/params/return are ignored by K1.M1 emit (K1.M2 extracts the
    real fn name)."""
    src = "@kernel fn k() -> i32 { 0 }\n"
    ptx = _kovc_self_host_emit_ptx("ptx_empty", src)
    expected = _PTX_HEADER + _ptx_entry(b"k()")
    assert ptx == expected, (
        f"PTX text mismatch:\n got={ptx!r}\nwant={expected!r}"
    )


def test_bootstrap_ptx_named_kernel():
    """K1.M2 (2026-05-28): the PTX entry name is the REAL kernel fn
    name, not a hardcoded 'k'. A @kernel fn `saxpy` emits
    `.visible .entry saxpy()`. Proves the bootstrap reads the fn name
    bytes from AST_FN_DECL slots 1/2 (name_start/name_len) and copies
    them into the PTX text -- the same source-byte read the bootstrap's
    `main` detection uses. Direct tile-IR -> PTX, NO MLIR."""
    src = "@kernel fn saxpy() -> i32 { 0 }\n"
    ptx = _kovc_self_host_emit_ptx("ptx_named", src)
    expected = _PTX_HEADER + _ptx_entry(b"saxpy()")
    assert ptx == expected, (
        f"PTX text mismatch:\n got={ptx!r}\nwant={expected!r}"
    )


def test_bootstrap_ptx_multi_kernel():
    """K1.M3 (2026-05-28): a module with multiple @kernel fns emits the
    PTX header once, then one `.visible .entry` per kernel (blank-line
    separated), mirroring Python ptx.py's emit_module loop. A
    single-kernel module stays byte-identical to K1.M1/M2 (no trailing
    blank), so empty_kernel / named_kernel stay green. Direct tile-IR
    -> PTX, NO MLIR."""
    src = "@kernel fn a() -> i32 { 0 }\n@kernel fn b() -> i32 { 0 }\n"
    ptx = _kovc_self_host_emit_ptx("ptx_multi", src)
    expected = (
        _PTX_HEADER + _ptx_entry(b"a()") + b"\n" + _ptx_entry(b"b()")
    )
    assert ptx == expected, (
        f"PTX text mismatch:\n got={ptx!r}\nwant={expected!r}"
    )


def test_bootstrap_ptx_kernel_params():
    """K1.M4 (2026-05-28): kernel params emit as positional
    `.param .b64 param_N` inside the .entry parens (v0.1: all params
    .b64, mirroring Python ptx.py _format_param; the PTX param name is
    positional, not the source name). Comma-space separated. Zero-param
    kernels keep empty parens, so empty/named/multi stay green. Direct
    tile-IR -> PTX, NO MLIR."""
