def test_bootstrap_ptx_tile_dtype_f32():
    """K1.GPU-TILE (2026-05-30): a `tile<f32, [N], HBM>` kernel param adopts its
    ELEMENT dtype (f32), so indexed load/store/arith emit FLOAT PTX
    (ld.global.f32 / add.f32 / st.global.f32) -- matching Python's
    backend/ptx.py -- instead of the u32/s32 INTEGER ops the bootstrap emitted
    before (it parsed `tile<...>` but DROPPED the element type, defaulting to
    i32 -> u32 ld/st on float data). The fix captures the first generic-arg
    IDENT of a `tile<ELEM,...>` param in parse_fn_decl and tags the param with
    ty_ident_to_tag(ELEM). Substring-asserted (not byte-golden) so it survives
    the later BB0/version chunks. GPU chunk 1 of docs/GPU_PTX_PARITY_SCOPING.md."""
    src = ("@kernel fn vadd(a: tile<f32, [256], HBM>, b: tile<f32, [256], HBM>, "
           "c: tile<f32, [256], HBM>) { let i = thread_idx(); c[i] = a[i] + b[i]; }\n")
    ptx = _kovc_self_host_emit_ptx("ptx_tile_f32", src).decode("utf-8", "replace")
    assert "ld.global.f32" in ptx, ptx
    assert "add.f32" in ptx, ptx
    assert "st.global.f32" in ptx, ptx
    assert "ld.global.u32" not in ptx, ptx
    assert "add.s32" not in ptx, ptx


def test_bootstrap_ptx_tile_dtype_i32():
    """K1.GPU-TILE (2026-05-30) contrastive: a `tile<i32,...>` param adopts i32,
    so load/store/arith stay INTEGER (ld.global.u32 / add.s32) -- confirming the
    tile-element extraction is dtype-CORRECT, not blanket-float. The
    u32-vs-Python-s32 signedness is a separate cosmetic chunk (GPU chunk 3)."""
    src = ("@kernel fn vadd(a: tile<i32, [256], HBM>, b: tile<i32, [256], HBM>, "
           "c: tile<i32, [256], HBM>) { let i = thread_idx(); c[i] = a[i] + b[i]; }\n")
    ptx = _kovc_self_host_emit_ptx("ptx_tile_i32", src).decode("utf-8", "replace")
    assert "ld.global.u32" in ptx, ptx
    assert "add.s32" in ptx, ptx
    assert "ld.global.f32" not in ptx, ptx


def test_bootstrap_run_process_exit_codes():
    """T1 (2026-05-30): the run_process(path: STRLIT) -> i32 builtin lets a
    compiled Helix program fork(57) + execve(59, path) + wait4(61) a binary
    and capture its decoded exit code ((wstatus >> 8) & 0xFF). This is the
    process-exec prerequisite for a Helix-native test runner (test-infra T1,
    docs/TEST_INFRA_PORT_SCOPING.md). The bootstrap previously emitted only
    read/write/open/close/exit syscalls. /bin/true -> 0, /bin/false -> 1."""
    rc_true, _, _ = _kovc_self_host_compile_and_run_full(
        "run_process_true", 'fn main() -> i32 { run_process("/bin/true") }')
    assert rc_true == 0, f"run_process(/bin/true) expected 0, got {rc_true}"
    rc_false, _, _ = _kovc_self_host_compile_and_run_full(
        "run_process_false", 'fn main() -> i32 { run_process("/bin/false") }')
    assert rc_false == 1, f"run_process(/bin/false) expected 1, got {rc_false}"


def test_bootstrap_set_exec_makes_runnable():
    """T2 (2026-05-30): set_exec(path) chmod 0o755's a file so a freshly
    write_file_to_arena'd program (mode 0644) becomes executable for
    run_process. Validates the full Helix-native test-runner primitive chain:
    write_file -> set_exec -> run_process -> exit code. A shebang script
    `#!/bin/sh\\nexit 7` written + set_exec'd + run returns 7; WITHOUT set_exec
    the non-exec file fails execve (EACCES) -> the child exits 127."""
    # "#!/bin/sh\nexit 7\n" = 35 33 47 98 105 110 47 115 104 10 101 120 105 116 32 55 10
    push = ("__arena_push(35); __arena_push(33); __arena_push(47); __arena_push(98); "
            "__arena_push(105); __arena_push(110); __arena_push(47); __arena_push(115); "
            "__arena_push(104); __arena_push(10); __arena_push(101); __arena_push(120); "
            "__arena_push(105); __arena_push(116); __arena_push(32); __arena_push(55); "
            "__arena_push(10);")
    with_se = ('fn main() -> i32 { let s = __arena_len(); ' + push +
               ' let n = __arena_len() - s; write_file_to_arena("/tmp/se_t1.sh", s, n); '
               'set_exec("/tmp/se_t1.sh"); run_process("/tmp/se_t1.sh") }')
    without_se = ('fn main() -> i32 { let s = __arena_len(); ' + push +
                  ' let n = __arena_len() - s; write_file_to_arena("/tmp/se_t2.sh", s, n); '
                  'run_process("/tmp/se_t2.sh") }')
    rc_exec, _, _ = _kovc_self_host_compile_and_run_full("set_exec_yes", with_se)
    assert rc_exec == 7, f"write+set_exec+run expected 7, got {rc_exec}"
    rc_noexec, _, _ = _kovc_self_host_compile_and_run_full("set_exec_no", without_se)
    assert rc_noexec == 127, f"write+run without set_exec expected 127, got {rc_noexec}"


def test_bootstrap_test_runner_skeleton():
    """T2 STEP A (2026-05-30): the Helix-native test-RUNNER LOOP, proven in
    compiled Helix (no Python). A multi-fn program: write_script writes a
    `#!/bin/sh\\nexit <d>` shebang to a fixed path; run_one does
    write_file -> set_exec -> run_process -> compare exit code to expected,
    returning 1 on mismatch; main tallies failures across several programs and
    returns the fail count. Proves the orchestration logic (helper fns,
    write/chmod/run sequencing, exit-code compare, pass/fail tally, status
    return) works end to end. All-pass -> 0; one deliberately-wrong expected
    -> 1. (STEP B wires compiling each test program via a fixed-path kovc.)"""
    helpers = (
        "fn write_script(code_byte: i32) -> i32 { let s = __arena_len(); "
        "__arena_push(35); __arena_push(33); __arena_push(47); __arena_push(98); "
        "__arena_push(105); __arena_push(110); __arena_push(47); __arena_push(115); "
        "__arena_push(104); __arena_push(10); __arena_push(101); __arena_push(120); "
        "__arena_push(105); __arena_push(116); __arena_push(32); __arena_push(code_byte); "
        "let n = __arena_len() - s; write_file_to_arena(\"/tmp/r_t.sh\", s, n); 0 } "
        "fn run_one(code_byte: i32, expected: i32) -> i32 { write_script(code_byte); "
        "set_exec(\"/tmp/r_t.sh\"); let rc = run_process(\"/tmp/r_t.sh\"); "
        "if rc == expected { 0 } else { 1 } } ")
    runner_pass = helpers + (
        "fn main() -> i32 { let f1 = run_one(48, 0); let f2 = run_one(55, 7); "
        "let f3 = run_one(53, 5); f1 + f2 + f3 }")
    runner_fail = helpers + (
        "fn main() -> i32 { let f1 = run_one(48, 0); let f2 = run_one(55, 9); "
        "let f3 = run_one(53, 5); f1 + f2 + f3 }")
    rc_pass, _, _ = _kovc_self_host_compile_and_run_full("test_runner_pass", runner_pass)
    assert rc_pass == 0, f"runner all-pass expected 0 failures, got {rc_pass}"
    rc_fail, _, _ = _kovc_self_host_compile_and_run_full("test_runner_fail", runner_fail)
    assert rc_fail == 1, f"runner one-fail expected 1 failure, got {rc_fail}"


def test_bootstrap_runner_compiles_and_runs_helix():
    """T2 STEP B (2026-05-30): the Helix-native runner COMPILES + RUNS a real
    Helix program (not just shell scripts). A fixed-path kovc (reads /tmp/t.hx
    -> writes /tmp/t.elf, built once via the _self_host_driver pattern + dropped
    at /tmp/kovc_t) is the runner's inner compiler. The Helix RUNNER program:
    write src -> /tmp/t.hx, run_process(/tmp/kovc_t) to COMPILE -> /tmp/t.elf,
    set_exec + run_process(/tmp/t.elf), compare exit code to expected. Proves the
    full compile->run->check cycle runs inside compiled Helix (Python only builds
    the kovc binary once; the K3 trusted seed replaces that). Distinct /tmp/t.*
    paths avoid ETXTBSY with the harness's own sh_drv_* driver."""
    import subprocess
    proj = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

    def _strip_demo(name):
        s = open(os.path.join(proj, "helixc", "bootstrap", name), encoding="utf-8").read()
        return s.rsplit(
            "// --------------------------------------------------------------\n// Demo:", 1)[0]

    lexer = _strip_demo("lexer.hx")
    parser_body = open(os.path.join(proj, "helixc", "bootstrap", "parser.hx"), encoding="utf-8").read()
    kovc_lib = _strip_demo("kovc.hx")
    in_path, out_path, kovc_t = "/tmp/t.hx", "/tmp/t.elf", "/tmp/kovc_t"
    k1_main = (
        "\nfn main() -> i32 {\n"
        "    let src_start = __arena_len();\n"
        f'    let src_len = read_file_to_arena("{in_path}");\n'
        "    let tok_base = __arena_len();\n"
        "    lex(src_start, src_len);\n"
        "    let ast_root = parse_top(tok_base);\n"
        "    let total = emit_elf_for_ast_to_path(ast_root);\n"
        "    let elf_start = __arena_len() - total;\n"
        f'    write_file_to_arena("{out_path}", elf_start, total)\n'
        "}\n")
    elf = _compile_src_to_elf(lexer + parser_body + kovc_lib + k1_main)
    subprocess.run(["wsl", "-e", "bash", "-c", f"cat > {kovc_t} && chmod +x {kovc_t}"],
                   input=elf, check=True, timeout=30)

    def _runner(prog: bytes, expected: int) -> str:
        push = "".join(f"__arena_push({b}); " for b in prog)
        return ("fn main() -> i32 { let s = __arena_len(); " + push +
                f'let n = __arena_len() - s; write_file_to_arena("{in_path}", s, n); '
                f'set_exec("{kovc_t}"); run_process("{kovc_t}"); '
                f'set_exec("{out_path}"); let rc = run_process("{out_path}"); '
                f"if rc == {expected} {{ 0 }} else {{ 1 }} }}")

    rc_ok, _, _ = _kovc_self_host_compile_and_run_full(
        "runner_compile_ok", _runner(b"fn main() -> i32 { 42 }", 42))
    assert rc_ok == 0, f"runner compile+run 42 (expect 42) -> 0, got {rc_ok}"
    rc_bad, _, _ = _kovc_self_host_compile_and_run_full(
        "runner_compile_bad", _runner(b"fn main() -> i32 { 7 }", 42))
    assert rc_bad == 1, f"runner compile+run 7 (expect 42) -> 1, got {rc_bad}"


def test_bootstrap_test_runner_over_corpus_subset():
    """T2 STEP C (2026-05-30): the Helix-native runner reproduces pytest's
    pass/fail over a SUBSET of the REAL CPU parity corpus -- the capstone that
    the Python test harness is REPLACEABLE. A generated Helix RUNNER, per
    (src, expected_rc) tuple, write_file's src -> /tmp/t.hx, run_process's the
    fixed-path kovc /tmp/kovc_t to compile -> /tmp/t.elf, set_exec+run_process's
    it, compares the exit code to expected_rc, tallies failures. All subset
    programs pass under the Helix runner exactly as under pytest -> 0; one
    deliberately-wrong expected -> 1. (Python only builds the kovc binary once;
    the K3 trusted seed replaces that. The bootstrap kovc has no stdlib
    auto-include, but every CPU-parity src is self-contained.)"""
    import subprocess
    from helixc.tests.test_parity_matrix import PARITY_CORPUS
    proj = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

    def _strip_demo(name):
        s = open(os.path.join(proj, "helixc", "bootstrap", name), encoding="utf-8").read()
        return s.rsplit(
            "// --------------------------------------------------------------\n// Demo:", 1)[0]

    in_path, out_path, kovc_t = "/tmp/t.hx", "/tmp/t.elf", "/tmp/kovc_t"
    k1_main = (
        "\nfn main() -> i32 {\n    let src_start = __arena_len();\n"
        f'    let src_len = read_file_to_arena("{in_path}");\n    let tok_base = __arena_len();\n'
        "    lex(src_start, src_len);\n    let ast_root = parse_top(tok_base);\n"
        "    let total = emit_elf_for_ast_to_path(ast_root);\n    let elf_start = __arena_len() - total;\n"
        f'    write_file_to_arena("{out_path}", elf_start, total)\n}}\n')
    driver = (_strip_demo("lexer.hx")
              + open(os.path.join(proj, "helixc", "bootstrap", "parser.hx"), encoding="utf-8").read()
              + _strip_demo("kovc.hx") + k1_main)
    subprocess.run(["wsl", "-e", "bash", "-c", f"cat > {kovc_t} && chmod +x {kovc_t}"],
                   input=_compile_src_to_elf(driver), check=True, timeout=30)

    def _gen_runner(tuples):
        check = ('fn check(expected: i32) -> i32 { set_exec("' + kovc_t + '"); run_process("' + kovc_t
                 + '"); set_exec("' + out_path + '"); let rc = run_process("' + out_path
                 + '"); if rc == expected { 0 } else { 1 } } ')
        body = ["fn main() -> i32 { let mut fails = 0; "]
        for i, (src, exp) in enumerate(tuples):
            push = "".join(f"__arena_push({b}); " for b in src.encode("utf-8"))
            body.append(f"let s{i} = __arena_len(); {push}let n{i} = __arena_len() - s{i}; "
                        f'write_file_to_arena("{in_path}", s{i}, n{i}); fails = fails + check({exp}); ')
        body.append("fails }")
        return check + "".join(body)

    # 32 short self-contained CPU programs (scaled from 8 on 2026-05-30 after the
    # task-14 fix, commit 6854909). The earlier ~11-block cap was the large-function
    # HOST STACK OVERFLOW: the runner inlines each program's bytes as __arena_push
    # statements, so N programs make a `main` of ~sum(len)+4N statements, and the
    # bootstrap's recursive AST_SEQ codegen overflowed the host stack at ~290. Now
    # that emit_ast_code + expr_type walk the spine ITERATIVELY the ceiling is
    # >=2000, so 32 programs (~1026 stmts) fit with 2x margin. Scaling to the full
    # ~720 corpus still needs a loop/manifest-driven runner with a FIXED-size main
    # (one loop reading each program from a file) -- which needs a dynamic-path read
    # builtin (T1 follow-up), since read_file_to_arena takes a compile-time strlit.
    subset = [(c[2], c[3]) for c in PARITY_CORPUS if len(c[2]) < 40][:32]
    rc_all, _, _ = _kovc_self_host_compile_and_run_full("corpus_runner_all", _gen_runner(subset))
    assert rc_all == 0, (
        f"Helix runner over {len(subset)} corpus programs expected 0 failures, got {rc_all}")
    corrupt = subset[:]
    mid = len(corrupt) // 2
    corrupt[mid] = (corrupt[mid][0], corrupt[mid][1] + 99)
    rc_one, _, _ = _kovc_self_host_compile_and_run_full("corpus_runner_corrupt", _gen_runner(corrupt))
    assert rc_one == 1, f"Helix runner with 1 wrong expected expected 1 failure, got {rc_one}"


def test_bootstrap_large_main_statement_sequence():
    """Regression for the large-function HOST-STACK-OVERFLOW bug (task #14,
    root-caused 2026-05-30). It was NEVER data corruption -- the earlier xfail
    premise was wrong. A function's statements are stored as a right-nested
    AST_SEQ chain; the bootstrap's code emitter (emit_ast_code) AND its type
    inference (expr_type, run on every fn body by the body/return-type trap)
    each recursed one host-stack frame per statement, so a main with a few
    hundred statements overflowed the stack MID-COMPILE (SIGSEGV -> empty ELF;
    proven: under `ulimit -s unlimited` the same source compiled fine). Both
    were converted to iterative right-spine walks (byte-identical output, so
    the self-host fixpoint is preserved), raising the ceiling from ~290 to
    >=2000 statements. Here a local `d` (=23) computed early must survive a
    1000-statement body and return correct -- the original repro was 400."""
    src = ("fn main() -> i32 { let s = __arena_len(); "
           + "__arena_push(65); " * 23
           + "let d = __arena_len() - s; "
           + "__arena_push(66); " * 1000
           + "d }")
    rc, _, _ = _kovc_self_host_compile_and_run_full("large_main_seq", src)
    assert rc == 23, f"local d (=23) held across 1000 inlined pushes should be 23, got {rc}"


@pytest.mark.xfail(strict=False, reason=(
    "Remaining recursion-depth limit (task #14 follow-up, 2026-05-30): after the "
    "codegen-side fix (emit_ast_code + expr_type are now iterative), the deepest "
    "always-on recursion left is the recursive-descent PARSER itself. It builds "
    "the let-chain (parse_let -> parse_expr at parser.hx:6908) and the statement "
    "SEQ-chain (parse_expr self-call ~2167/2182) one host-stack frame per "
    "statement, so a function with ~200+ flat `let` bindings overflows the stack "
    "DURING PARSING (SIGSEGV, empty ELF). Fixing it needs an explicit parse "
    "work-stack to flatten construction while preserving the right-nested tree "
    "(output byte-identity depends on tree STRUCTURE, not arena positions). Only "
    "pathological flat functions hit this: the self-compile and the Helix test "
    "runner use bounded-depth functions, and the push/statement form already "
    "works to >=2000 (see test_bootstrap_large_main_statement_sequence). Tracked "
    "as the parser-iterativization follow-up (with walk_for_panic)."))
def test_bootstrap_large_let_chain_parser_recursion_xfail():
    """~318 sequential `let` bindings overflow the recursive-descent parser's
    host stack during parsing (heavier parse_let frames overflow earlier, ~200,
    than the ~2000 SEQ-statement ceiling). Flips to xpass when parse_expr /
    parse_let are made iterative -> then remove the xfail."""
    src = ("fn main() -> i32 { "
           + "".join(f"let v{i} = {i % 7}; " for i in range(318))
           + "42 }")
    rc, _, _ = _kovc_self_host_compile_and_run_full("large_let_chain", src)
    assert rc == 42, f"318 let-bindings should return 42, got {rc}"


def test_bootstrap_bigstack_deep_recursion():
    """Regression for the big-stack entry stub (task 16 / bug #1, 2026-05-30).
    Every bootstrap-emitted binary now begins with an _start stub that mmaps a
    512 MiB stack and switches rsp before calling main, so deep RUNTIME
    recursion no longer overflows the kernel's default 8 MB stack. A
    self-recursion 20000 frames deep (~80 MB at the 4 KB-per-frame prologue)
    returns 7; before the stub it SIGSEGV'd (rc 139) for any depth >~2500
    (measured: rec(2000) ok, rec(5000) -> 139, rec(100000) -> 7 with the stub).
    Bootstrap-side half of closing the self-host stack limit -- the canonical
    test_bootstrap_kovc_self_host_loop still needs the matching stub in the
    Python backend for its Python-built K1 (see that test's skip note)."""
    src = ("fn rec(n: i32) -> i32 { if n == 0 { 7 } else { rec(n - 1) } } "
           "fn main() -> i32 { rec(20000) }")
    rc, _, _ = _kovc_self_host_compile_and_run_full("bigstack_deep_rec", src)
    assert rc == 7, f"20000-deep recursion should return 7 on the mmap'd stack, got {rc}"


def test_bootstrap_seed_driver_self_rebuild():
    """K3 chunk 2 (2026-05-30): a HELIX-NATIVE seed driver rebuilds the compiler
    end-to-end with NO Python orchestration and NO external ulimit. The seed is
    [lexer + parser + kovc + seed_main] -- a full compiler whose main reads the 3
    bootstrap source files (read_file_to_arena APPENDS at the arena cursor, so the
    files concatenate for free), prepends a driver main placed FIRST (so
    resolve_program_root selects it and demo-stripping is unnecessary), compiles
    the assembly via lex/parse_top/emit_elf_for_ast_to_path into K-next, then
    validates K-next by having it compile `6*7` and running the result (-> 42).

    The seed must be built by K1 (the bootstrap), not the Python reference
    compiler, because seed_main uses the run_process/set_exec builtins that exist
    only in kovc.hx. K1 is Python-built (no big-stack stub), so building the
    1.43 MB seed needs ulimit; but the seed BINARY carries the task-16 big-stack
    _start stub, so it runs and self-compiles WITHOUT ulimit -- proving the
    bootstrap can drive its own rebuild + self-validation in Helix."""
    import os, subprocess
    proj = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
    SEP = "// --------------------------------------------------------------\n// Demo:"

    def lib(name, strip):
        s = open(os.path.join(proj, "helixc", "bootstrap", name), encoding="utf-8").read()
        return s.rsplit(SEP, 1)[0] if strip else s

    for name, dst, strip in [("lexer.hx", "/tmp/sd_lexer.hx", True),
                             ("parser.hx", "/tmp/sd_parser.hx", False),
                             ("kovc.hx", "/tmp/sd_kovc.hx", True)]:
        subprocess.run(["wsl", "-e", "bash", "-c", f"cat > {dst}"],
                       input=lib(name, strip).encode("utf-8"), check=True, timeout=30)

    knext_main = ('fn main() -> i32 { let s = __arena_len(); '
        'let n = read_file_to_arena("/tmp/sd_in.hx"); let t = __arena_len(); lex(s, n); '
        'let a = parse_top(t); let tot = emit_elf_for_ast_to_path(a); '
        'let es = __arena_len() - tot; write_file_to_arena("/tmp/sd_out.bin", es, tot) } ')
    kn = "".join(f"__arena_push({b}); " for b in knext_main.encode("utf-8"))
    tp = "".join(f"__arena_push({b}); " for b in "fn main() -> i32 { 6 * 7 }".encode("utf-8"))
    seed_main = (
        'fn seed_rebuild() -> i32 { let src_start = __arena_len(); '
        + kn +
        'read_file_to_arena("/tmp/sd_lexer.hx"); read_file_to_arena("/tmp/sd_parser.hx"); '
        'read_file_to_arena("/tmp/sd_kovc.hx"); let total_src = __arena_len() - src_start; '
        'let tok_base = __arena_len(); lex(src_start, total_src); let ast_root = parse_top(tok_base); '
        'let elf_total = emit_elf_for_ast_to_path(ast_root); let elf_start = __arena_len() - elf_total; '
        'write_file_to_arena("/tmp/sd_knext.bin", elf_start, elf_total); '
        'let tp_start = __arena_len(); ' + tp + 'let tp_len = __arena_len() - tp_start; '
        'write_file_to_arena("/tmp/sd_in.hx", tp_start, tp_len); '
        'set_exec("/tmp/sd_knext.bin"); run_process("/tmp/sd_knext.bin"); '
        'set_exec("/tmp/sd_out.bin"); let rc = run_process("/tmp/sd_out.bin"); rc } '
        'fn main() -> i32 { seed_rebuild() } ')
    seed_source = lib("lexer.hx", True) + lib("parser.hx", False) + lib("kovc.hx", True) + seed_main

    drv, in_path, out_path = _self_host_driver()
    subprocess.run(["wsl", "-e", "bash", "-c", f"cat > {in_path}"],
                   input=seed_source.encode("utf-8"), check=True, timeout=30)
    subprocess.run(["wsl", "-e", "bash", "-c",
                    f"rm -f {out_path}; ulimit -s unlimited; chmod +x {drv} && {drv}"], timeout=180)
    subprocess.run(["wsl", "-e", "bash", "-c", f"cp {out_path} /tmp/sd_seed.bin"], check=True, timeout=10)
    out = ""
    for _ in range(2):  # retry once on a cold-WSL flake (lesson 10)
        r = subprocess.run(["wsl", "-e", "bash", "-c",
            "rm -f /tmp/sd_knext.bin /tmp/sd_out.bin; chmod +x /tmp/sd_seed.bin && /tmp/sd_seed.bin; echo RC=$?"],
            capture_output=True, timeout=120)
        out = r.stdout.decode("utf-8", "replace")
        if "RC=42" in out:
            break
    assert "RC=42" in out, f"Helix seed self-rebuild should validate K-next via 6*7 -> 42, got: {out[-200:]!r}"


def test_bootstrap_ptx_tile_zeros():
    """K1.M13 (2026-05-28): FIRST GPU tile op -- __tile_zeros(N, M)
    lowers to N*M consecutive `mov.f32 %fX, 0f00000000;` register-fills
    (the register-tile model, mirroring Python backend/ptx.py TILE_ZEROS
    / Stage 64 Inc 2). The CALL already parses -- the x86 CPU path
    (K1.F23c) uses the same 2-arg signature -- so this is the first GPU
    tile primitive with NO parser change; the tile elementwise/matmul arc
    starts here. 0f00000000 is the PTX hex literal for +0.0f.
    ptxas-validated (real SASS). Direct tile-IR -> PTX, NO MLIR, NO CUDA."""
    src = "@kernel fn k() -> i32 { __tile_zeros(2, 2) }\n"
    ptx = _kovc_self_host_emit_ptx("ptx_tilezeros", src)
    expected = _PTX_HEADER + (
        b".visible .entry k()\n"
        b"{\n"
        + _PTX_REG_BLOCK
        + b"    mov.f32 %f0, 0f00000000;\n"
        + b"    mov.f32 %f1, 0f00000000;\n"
        + b"    mov.f32 %f2, 0f00000000;\n"
        + b"    mov.f32 %f3, 0f00000000;\n"
        + b"    ret;\n"
        b"}\n"
    )
    assert ptx == expected, (
        f"PTX text mismatch:\n got={ptx!r}\nwant={expected!r}"
    )
    if _ptxas_available():
        import subprocess
        r = subprocess.run(
            ["wsl", "-e", "bash", "-c",
             "ptxas --gpu-name sm_75 -o /tmp/ptx_tilezeros.cubin "
             "/tmp/sh_ptx_tilezeros_out.ptx 2>&1"],
            capture_output=True, timeout=30,
        )
        assert r.returncode == 0, (
            f"ptxas rejected tile-zeros PTX (rc={r.returncode}): "
            f"{r.stdout.decode(errors='replace')}"
        )


def test_bootstrap_ptx_tile_add():
    """K1.M14 (2026-05-28): FIRST GPU tile COMPUTE op -- __tile_add(a, b,
    dst, count) elementwise-adds two register-tiles into a third over
    `count` consecutive %f registers (mirroring Python backend/ptx.py
    TILE_ADD / Stage 64 Inc 3). a/b/dst are vars bound to prior
    __tile_zeros results (their %f base); count is a static literal.
    Together with __tile_zeros (M13) this is a complete on-GPU tile
    elementwise pipeline -- the AI-matrix-primitive arc's first compute.
    ptxas-validated (real SASS). Direct tile-IR -> PTX, NO MLIR, NO CUDA."""
    src = ("@kernel fn k() -> i32 { "
           "let a: f32 = __tile_zeros(2, 2); "
           "let b: f32 = __tile_zeros(2, 2); "
           "let c: f32 = __tile_zeros(2, 2); "
           "__tile_add(a, b, c, 4) }\n")
    ptx = _kovc_self_host_emit_ptx("ptx_tileadd", src)
    expected = _PTX_HEADER + (
        b".visible .entry k()\n"
        b"{\n"
        + _PTX_REG_BLOCK
        + b"    mov.f32 %f0, 0f00000000;\n"
        + b"    mov.f32 %f1, 0f00000000;\n"
        + b"    mov.f32 %f2, 0f00000000;\n"
        + b"    mov.f32 %f3, 0f00000000;\n"
        + b"    mov.f32 %f4, 0f00000000;\n"
        + b"    mov.f32 %f5, 0f00000000;\n"
        + b"    mov.f32 %f6, 0f00000000;\n"
        + b"    mov.f32 %f7, 0f00000000;\n"
        + b"    mov.f32 %f8, 0f00000000;\n"
        + b"    mov.f32 %f9, 0f00000000;\n"
        + b"    mov.f32 %f10, 0f00000000;\n"
        + b"    mov.f32 %f11, 0f00000000;\n"
        + b"    add.f32 %f8, %f0, %f4;\n"
        + b"    add.f32 %f9, %f1, %f5;\n"
        + b"    add.f32 %f10, %f2, %f6;\n"
        + b"    add.f32 %f11, %f3, %f7;\n"
        + b"    ret;\n"
        b"}\n"
    )
    assert ptx == expected, (
        f"PTX text mismatch:\n got={ptx!r}\nwant={expected!r}"
    )
    if _ptxas_available():
        import subprocess
        r = subprocess.run(
            ["wsl", "-e", "bash", "-c",
             "ptxas --gpu-name sm_75 -o /tmp/ptx_tileadd.cubin "
             "/tmp/sh_ptx_tileadd_out.ptx 2>&1"],
            capture_output=True, timeout=30,
        )
        assert r.returncode == 0, (
            f"ptxas rejected tile-add PTX (rc={r.returncode}): "
            f"{r.stdout.decode(errors='replace')}"
        )


