def test_bootstrap_kovc_k1f11_14_exactly_type_guard_self_host():
    """K3.F (2026-05-27): audit-clean fail-closed verification for the
    K1.F11/F12/F13/F14 mixed-type comparison widening batch.

    The K3.B audit discipline requires the widening guard to fail-
    closed when the non-64-bit operand is NOT exactly the expected
    type (i32 for signed, u32 for unsigned, f32 for float). Without
    this guard, u32/u8/u16/i8/i16/f32/bf16 mixed with i64 would be
    silently sign-extended (when they should be zero-extended or
    rejected) -- a silent-failure class the K3.B fix originally
    closed for K1.F8.

    This test probes 6 fail-closed paths in the K1.F11-F14 batch:
      - i64 < u32  -- trap 6020 (signed/unsigned mismatch on r)
      - u32 < i64  -- trap 6021 (signed/unsigned mismatch on l)
      - u64 < i32  -- trap 6030 (signed i32 vs unsigned u64)
      - i32 < u64  -- trap 6031 (mirror)
      - f64 < i32  -- trap 6010 (int treated as float-bits would
                                  silently miscompile)
      - i32 < f64  -- trap 6011 (mirror)

    Each program must SIGILL (exit code 132 = 128+SIGILL) instead of
    completing with a silent miscompile (rc=42 or rc=0).

    Audit-clean signal recorded for K1.F11-F14 batch in
    K_BOOTSTRAP_HARD_CONSTRAINT.md after this test passes.
    """
    cases = [
        ("k3f_audit_i64_lt_u32", "if 30_i64 < 60_u32 { 42 } else { 0 }"),
        ("k3f_audit_u32_lt_i64", "if 30_u32 < 60_i64 { 42 } else { 0 }"),
        ("k3f_audit_u64_lt_i32", "if 30_u64 < 60 { 42 } else { 0 }"),
        ("k3f_audit_i32_lt_u64", "if 30 < 60_u64 { 42 } else { 0 }"),
        ("k3f_audit_f64_lt_i32", "if 30.0_f64 < 60 { 42 } else { 0 }"),
        ("k3f_audit_i32_lt_f64", "if 30 < 60.0_f64 { 42 } else { 0 }"),
    ]
    for name, predicate in cases:
        rc = _kovc_self_host_compile_and_run(
            name,
            f"fn main() -> i32 {{ {predicate} }}",
        )
        # rc=132 = SIGILL from ud2 in emit_trap_with_id. Confirms
        # the K3.B-style guard fired (any rc != 132 would indicate a
        # silent-failure bug class).
        assert rc == 132, (
            f"K3.F audit {name}: expected trap (rc=132); got rc={rc}. "
            f"Bug class: K3.B-style exactly-type guard missed the case."
        )


def test_bootstrap_kovc_k1f15_f16_bit_pattern_self_host():
    """K1.F15b (2026-05-27): pin the f16 bit pattern is genuinely IEEE-754
    half-precision (1+5+10), not the bf16-shaped truncation that the
    K1.BH first-cut did.

    The f16 literal codegen emits emit_ast_int(f16_bits) -- the bits
    live in eax. __bits_of_f32 is an identity bitcast (no extra
    bytes; same eax) typed as i32, so the function body returns the
    bit pattern as i32 without tripping the body-vs-ret-ty width
    mismatch trap.

    Verification values (low byte distinguishes f16 from bf16 since
    both 1.0 and 2.0 have low byte 0 in either encoding -- we need
    a value with mantissa bits below position 8):

      1.125_f16:
        binary 1.001 -> fractional bit at 2^-3 -> mantissa bit 7 of
        the 10-bit field (bit 9 = 2^-1, bit 8 = 2^-2, bit 7 = 2^-3) ->
        mantissa = 2^7 = 128.
        Exp(1.125) unbiased = 0, biased = 15.
        bits = (0 << 15) | (15 << 10) | 128 = 15360 + 128 = 15488 = 0x3C80
        Low byte: 0x80 = 128

      vs 1.125_bf16 (storage convention in bootstrap differs):
        The K1.F2 bf16 codegen takes f32(1.125) = 0x3F900000 and
        AND-masks with 0xFFFF0000 (`bits & 0 - 65536`), yielding
        0x3F900000 -- the bf16 bits live in the TOP 16 of a 32-bit
        i32 slot, with the low 16 zeroed. So __bits_of_f32(1.125_bf16)
        returns 0x3F900000 in eax, low byte = 0x00 = 0.
        (This is a bootstrap-specific storage convention: bf16 is
        i32-shaped with bits in the high half, while f16 is i32-
        shaped with bits in the low half. Both are 4-byte slots; the
        bit-position difference matters only for raw __bits_of_f32
        extraction. Arith on either traps via is_bf16_expr.)

    So the expected bootstrap exit code for `__bits_of_f32(1.125_f16)`
    is 128 (low byte of 0x3C80) and for `__bits_of_f32(1.125_bf16)`
    is 0 (low byte of 0x3F900000). Different values prove the f16
    path uses the new f32_to_f16_bits helper rather than the bf16
    mask-and-shift-up.
    """
    # 1.125_f16: confirm low byte = 128 (IEEE-754 half, not bf16-truncated).
    rc = _kovc_self_host_compile_and_run(
        "k1f15b_1p125_f16",
        "fn main() -> i32 { __bits_of_f32(1.125_f16) }",
    )
    # Bit pattern is 15488 = 0x3C80. Linux exit code = rc & 0xFF = 0x80 = 128.
    assert rc == 128, (
        f"K1.F15b 1.125_f16 bits: expected exit code 128 (low byte of 0x3C80, "
        f"the IEEE-754 half pattern); got {rc}. If rc=144 the bootstrap "
        f"regressed to bf16-shaped bits."
    )

    # Regression: 1.125_bf16 stores bits in the top 16 of i32 (low 16
    # cleared via mask). Bit pattern 0x3F900000; low byte = 0x00 = 0.
    # Distinguishes the bf16 storage convention from f16's low-16
    # convention (which gave 128 above).
    rc_bf = _kovc_self_host_compile_and_run(
        "k1f15b_1p125_bf16",
        "fn main() -> i32 { __bits_of_f32(1.125_bf16) }",
    )
    assert rc_bf == 0, (
        f"K1.F15b 1.125_bf16 bits regression: expected 0 (low byte of "
        f"0x3F900000, with bf16 bits in the high half); got {rc_bf}."
    )

    # K1.F18 (2026-05-27): round-to-nearest-even was added in the
    # f32_to_f16_bits helper. An empirical probe is omitted here
    # because the parse_float_bits accumulator is i32 and traps via
    # the >9-digit overflow guard for any literal precise enough to
    # trigger the round-bit path (round_bit=1 requires the dropped
    # mantissa bits 0..12 to encode a value >= 4096, which in
    # decimal needs >9 significant digits past the implicit 1.).
    # The rounding logic is verified by inline reading of the helper
    # (audit-clean recorded in K3.H follow-up). 1.125_f16 above does
    # NOT trigger the round-bit path (round_bit==0), so the regression
    # test still pins the conversion's structural correctness.


def test_bootstrap_kovc_k1f18b_f16_denormal_self_host():
    """K1.F18b (2026-05-27): IEEE-754 gradual underflow / f16 denormals.

    Before K1.F18b, any f32 with unbiased exponent < -14 flushed to
    +/-0 when converted to f16. K1.F18b restores the proper f16-
    denormal representation for unbiased exponents in [-25, -15], so
    values in [~2^-25, 2^-14) now produce a non-zero f16 bit pattern.
    unbiased < -25 still flushes.

    The two probes below were chosen so the bootstrap's
    parse_float_bits (a small-iteration-count, low-overflow-risk
    integer reconstruction) reproduces the expected f32 bits, and so
    K1.F18b's denormal formula then yields a distinguishing non-zero
    low byte. Deeper-iteration literals like 0.0000005_f16 would also
    hit denormals in principle, but they expose a pre-existing
    parse_float_bits arithmetic divergence at 20+ halvings (low byte
    132 != Python-trace 0 on master), out of K1.F18b's scope.

      0.00005_f16 (truncation-only denormal):
        parse_float_bits -> unbiased=-15, mant32=5592405 (alternating-
          bit residual pattern from v_scaled=5 over threshold=3, the
          closest-truncated 2^-15-fit).
        K1.F18b: shift = 14, divisor = 16384.
          mant_with_lead = 13981013.
          mant10_trunc = 853, round_bit_pos = 8192.
          round_bit = (13981013/8192) & 1 = 1706 & 1 = 0 -> no round-up.
          mant10_rounded = 853. bits = 853 = 0x355. Low byte = 0x55 = 85.

      0.00004_f16 (RNE round-up denormal):
        parse_float_bits -> unbiased=-15, mant32=2796202.
        K1.F18b: shift = 14, divisor = 16384.
          mant_with_lead = 11184810.
          mant10_trunc = 682, round_bit_pos = 8192.
          round_bit = (11184810/8192) & 1 = 1365 & 1 = 1.
          sticky_nonzero = (11184810 & 8191) = 2730 != 0 -> 1.
          round_up = 1; mant10_rounded = 683. bits = 683 = 0x2AB. Low byte = 0xAB = 171.

    Both probes were 0 (flush) on K1.F18 master; both are non-zero
    on K1.F18b. The round-up probe also exercises the RNE sticky-OR
    path, the heart of K1.F18b's value over a plain truncation.

    Both also confirm the f16 storage convention: the bit pattern
    lives in the LOW 16 of the i32 slot, so the low byte equals the
    denormal mantissa low byte (mant10 & 0xFF).
    """
    # Probe 1: truncation-only denormal (round_bit=0).
    rc1 = _kovc_self_host_compile_and_run(
        "k1f18b_5em5_f16",
        "fn main() -> i32 { __bits_of_f32(0.00005_f16) }",
    )
    assert rc1 == 85, (
        f"K1.F18b 0.00005_f16 (unbiased=-15 denormal, mant10=853): "
        f"expected exit code 85 (low byte 0x55 of bits 0x0355); got "
        f"{rc1}. If rc=0, the f16 codegen regressed to K1.F18 "
        f"flush-to-zero subnormal behavior."
    )

    # Probe 2: RNE round-up denormal (round_bit=1, sticky=1).
    rc2 = _kovc_self_host_compile_and_run(
        "k1f18b_4em5_f16",
        "fn main() -> i32 { __bits_of_f32(0.00004_f16) }",
    )
    assert rc2 == 171, (
        f"K1.F18b 0.00004_f16 (unbiased=-15 denormal, round-up to "
        f"mant10=683): expected exit code 171 (low byte 0xAB of bits "
        f"0x02AB); got {rc2}. If rc=0, the denormal path flushed; if "
        f"rc=170, the RNE sticky-OR round-up failed."
    )


def test_bootstrap_kovc_k1f19_reflect_hash_real_mixer_self_host():
    """K1.F19 (2026-05-27): upgrade reflect_hash from the K1.F2 0-stub
    to a real FNV-style i32 mixer. The mixer is the same 24-byte
    sequence `__hash_i32` uses; the K1.F19 refactor extracts it into a
    shared `emit_hash_i32_mixer` helper so both builtins use one
    implementation.

    Hash formula (signed-32-bit imul throughout, results truncate):
        h = (x * x * c1) + (x * c2) + c3
    where c1=0x05EBCA6B, c2=0x27D4EB2F, c3=0x165667B1.

    Test cases:
      reflect_hash(1):
        h = (1*1*0x05EBCA6B) + (1*0x27D4EB2F) + 0x165667B1
          = 0x05EBCA6B + 0x27D4EB2F + 0x165667B1
          = 0x44171D4B = 1142365515
        Low byte = 0x4B = 75. Distinguishing from the K1.F2 0-stub (rc=0).

      reflect_hash(42):
        h = (42*42*c1) + (42*c2) + c3
          = 1764*c1 + 42*c2 + c3
          = 0x6C03C6B3 = 1812186803 (signed-32-bit wrap)
        Low byte = 0xB3 = 179. Pins the multiplicative mixing path.

    Both probes were 0 on K1.F2 master. The mixer also drives the
    pre-existing `__hash_i32` builtin so the shared-helper refactor
    is verified by the unchanged __hash_i32 contract.

    Python's reflect_hash semantic is content-addressable AST hashing;
    the bootstrap degenerate version hashes the LAST evaluated arg's
    i32 value (since args_head is variadic; K1.F16/F17's walk leaves
    the last value in eax before the mixer runs). For non-AST-reflection
    programs (every bootstrap-compileable program today), this is a
    strict upgrade in observability without breaking any prior contract.
    """
    # Probe 1: reflect_hash(1) -> 75 (low byte of mixer output).
    rc1 = _kovc_self_host_compile_and_run(
        "k1f19_reflect_hash_1",
        "fn main() -> i32 { reflect_hash(1) }",
    )
    assert rc1 == 75, (
        f"K1.F19 reflect_hash(1): expected exit code 75 (low byte 0x4B "
        f"of the FNV mixer output 0x44171D4B = 1142365515); got {rc1}. "
        f"If rc=0, the K1.F2 0-stub regressed back; if non-75, the "
        f"mixer formula or constants are corrupted."
    )

    # Probe 2: reflect_hash(42) -> 179.
    rc2 = _kovc_self_host_compile_and_run(
        "k1f19_reflect_hash_42",
        "fn main() -> i32 { reflect_hash(42) }",
    )
    assert rc2 == 179, (
        f"K1.F19 reflect_hash(42): expected exit code 179 (low byte "
        f"0xB3 of 0x6C03C6B3); got {rc2}. Pins the multiplicative "
        f"mixing path: x*x*c1 + x*c2 + c3 with c1=0x05EBCA6B."
    )


def test_bootstrap_kovc_k1f20_trace_event_passthrough_self_host():
    """K1.F20 (2026-05-27): __trace_event(args...) now returns the
    value of the LAST evaluated arg (a dbg!()-style value-tap) instead
    of always returning 0.

    K1.F3 (2026-05-26) emitted a closing `mov eax, 0` so the call
    returned 0 regardless of args. K1.F20 drops that closer; the
    K1.F16 variadic walk's last `emit_ast_code` already leaves the
    last arg's value in eax, so removing the closer is the entire
    change. A real trace-arena ring-buffer write is the K1.F20b
    followup — but that write will keep the same pass-through return
    contract, so this test pins K1.F20 and stays valid through K1.F20b.

    Test cases:

      __trace_event(99):
        Single-arg case. The walk emits AST_INT(99)'s code (mov eax,
        99 = 5 bytes), then returns. With the K1.F20 closer dropped,
        eax = 99 at return. rc = 99 & 0xFF = 99.

      __trace_event(1, 2, 7):
        Multi-arg case. The parser builds the call-args linked list
        FIFO: args_head = AST_ARG(1); next-ptr at slot+2 -> AST_ARG(2)
        -> AST_ARG(7) -> 0. K3.L (2026-05-27) audit-fix changed the
        walks from slot+3 (always 0, exited after iter 1) to slot+2
        (real next-ptr). After K3.L, the walk emits AST_INT(1), then
        AST_INT(2), then AST_INT(7); each emit overwrites eax. After
        the walk eax = 7 (the LAST source arg's value, the last to be
        emitted). rc = 7. This pins the K1.F16 variadic-walk closure's
        ACTUAL semantic now that the silent-arg-drop bug is fixed.

    Both probes were rc=0 on K1.F3 master.
    """
    rc1 = _kovc_self_host_compile_and_run(
        "k1f20_trace_event_one_arg",
        "fn main() -> i32 { __trace_event(99) }",
    )
    assert rc1 == 99, (
        f"K1.F20 __trace_event(99): expected exit code 99 (the last "
        f"arg's value after the K1.F16 walk, with the K1.F3 mov-eax-0 "
        f"closer dropped); got {rc1}. If rc=0, the K1.F3 0-stub "
        f"regressed; if neither 0 nor 99, the variadic walk is broken."
    )

    rc2 = _kovc_self_host_compile_and_run(
        "k1f20_trace_event_three_args",
        "fn main() -> i32 { __trace_event(1, 2, 7) }",
    )
    assert rc2 == 7, (
        f"K1.F20 / K3.L __trace_event(1, 2, 7): expected exit code 7 "
        f"(the LAST source arg, after the K3.L fix that made the K1.F16 "
        f"walk actually iterate via slot+2 next-ptr; pre-K3.L the walk "
        f"used slot+3 which was always 0, exiting after the first arg "
        f"and giving rc=1); got {rc2}. If rc=1, the K3.L fix regressed."
    )


def test_bootstrap_kovc_k1f20b_trace_ring_buffer_self_host():
    """K1.F20b (2026-05-27): __trace_event now writes the last walked
    arg's value to a fixed arena slot (CAP-65 = disp 8388352, one i32
    slot below the Quote cell-table at 8388356), and the new
    `__trace_last()` builtin reads that slot back.

    This converts trace_event from K1.F20's value-tap-only stub into a
    real depth-1 observable trace runtime. Programs can now write a
    value with `__trace_event(x)` and read it back with
    `__trace_last()` -- the simplest observable trace semantic that
    advances the trace-events Category-2 row beyond PARTIAL.

    Probes:

      __trace_event(42); __trace_last():
        trace_event(42) writes 42 to disp 8388352, returns 42 (value-tap
        contract from K1.F20 preserved). trace_last() reads the slot,
        returns 42. Exit code 42.

      __trace_event(11); __trace_event(99); __trace_last():
        Two trace_events in sequence -- the second OVERWRITES the slot
        (depth-1, not a ring). trace_last() returns the most-recent
        value, 99. Pins the "last value wins" semantic.

      __trace_last() with no prior trace_event:
        Reads the slot when it's still BSS-zero (no writes yet). Returns
        0. Confirms the slot starts zero (rather than e.g. uninitialised
        garbage that'd flake across runs).
    """
    rc1 = _kovc_self_host_compile_and_run(
        "k1f20b_trace_read_after_one_write",
        "fn main() -> i32 { __trace_event(42); __trace_last() }",
    )
    assert rc1 == 42, (
        f"K1.F20b __trace_event(42); __trace_last(): expected exit "
        f"code 42 (trace_event writes 42 to slot, trace_last reads "
        f"back 42); got {rc1}. If rc=0, the store didn't happen "
        f"(K1.F20b regressed to value-tap-only); if non-{{0,42}} the "
        f"slot disp or arena_base patching is broken."
    )

    rc2 = _kovc_self_host_compile_and_run(
        "k1f20b_trace_last_wins",
        "fn main() -> i32 { __trace_event(11); __trace_event(99); __trace_last() }",
    )
    assert rc2 == 99, (
        f"K1.F20b last-write-wins probe: expected exit code 99 (the "
        f"second trace_event overwrites the slot, trace_last returns "
        f"the most-recent value); got {rc2}. If rc=11, the slot is "
        f"append-only or the store address is wrong."
    )

    rc3 = _kovc_self_host_compile_and_run(
        "k1f20b_trace_last_bss_zero",
        "fn main() -> i32 { __trace_last() }",
    )
    assert rc3 == 0, (
        f"K1.F20b BSS-zero probe: expected exit code 0 (slot starts "
        f"zero before any trace_event); got {rc3}. Non-zero suggests "
        f"the slot disp lands inside a region the K2 runtime "
        f"populates at startup (which would flake across runs)."
    )


def test_bootstrap_kovc_k3j_trace_audit_fixes_self_host():
    """K3.J (2026-05-27): close two K1.F20b audit findings:

      MEDIUM-1 -- zero-arg __trace_event() corrupts the trace slot.
        The K1.F20b store was unconditional; for zero-arg calls eax
        holds caller-context residue, written silently to the slot.
        Fix: gate the store on args_head != 0; emit xor-eax-eax for
        deterministic 0 return on zero-arg calls (and don't disturb
        the prior recorded trace value).

      LOW-2 -- __trace_last(args) silently drops side effects.
        Other variadic-tolerant builtins (reflect_hash, __trace_event,
        __helix_*) walk args_head for side-effect preservation per
        the K1.F17 closure. __trace_last was the exception. Fix:
        walk args_head first, then load the trace slot.

    Probe A (MEDIUM-1 fix):
      __trace_event(77); __trace_event(); __trace_last()
        After K3.J: trace_event(77) stores 77 to slot; trace_event()
        is a no-op (slot still 77); trace_last() reads 77.
        Pre-K3.J: trace_event() would have overwritten the slot with
        whatever eax held -- often not 77.

    Probe B (LOW-2 fix):
      let mut x = 5; let _ = __trace_last(__trace_event(99)); x
        After K3.J: __trace_event(99) is evaluated as the arg to
        __trace_last -- it writes 99 to the trace slot and returns 99.
        __trace_last then reads the slot (=99) but its result is bound
        to _. The fn returns x=5.
        Pre-K3.J: __trace_last would have skipped its arg entirely;
        __trace_event(99) wouldn't fire; slot would be 0; same final
        return value (x=5) BUT the missing side-effect would be hidden.

      This probe pins "args evaluated for side effects" by structuring
      the program so the SAME final return value comes from a different
      execution path under the two semantics -- specifically, by also
      probing trace_last AFTER:
        __trace_last(__trace_event(99));   __trace_last()
        Under K3.J: first call writes 99 + reads, second call just
        reads -> 99.
        Pre-K3.J: __trace_event never fired -> slot still 0 ->
        second call -> 0.
    """
    rc_a = _kovc_self_host_compile_and_run(
        "k3j_zero_arg_trace_event_preserves_slot",
        "fn main() -> i32 { __trace_event(77); __trace_event(); __trace_last() }",
    )
    assert rc_a == 77, (
        f"K3.J MEDIUM-1 fix probe: expected exit code 77 (the prior "
        f"trace_event(77) stored 77; the subsequent zero-arg "
        f"trace_event() should NOT overwrite the slot); got {rc_a}. "
        f"If rc != 77, the K1.F20b unconditional-store regression is "
        f"back -- zero-arg trace_event is corrupting the slot."
    )

    rc_b = _kovc_self_host_compile_and_run(
        "k3j_trace_last_evaluates_args_for_side_effects",
        "fn main() -> i32 { __trace_last(__trace_event(99)); __trace_last() }",
    )
    assert rc_b == 99, (
        f"K3.J LOW-2 fix probe: expected exit code 99 (the first "
        f"trace_last call evaluates its arg __trace_event(99) for "
        f"side effects -- which writes 99 to the slot; the second "
        f"trace_last reads the slot = 99); got {rc_b}. If rc=0, the "
        f"trace_last arg was silently dropped -- trace_event(99) "
        f"never fired -- slot still BSS-zero. K1.F17 regression."
    )


def test_bootstrap_kovc_k1f21_generic_bare_call_fallback_self_host():
    """K1.F21 (2026-05-27): close matrix-row-137 limitation. Bare
    call `id(42)` to a generic fn -- where mono produced `id__i32`
    from a turbofish call elsewhere -- previously SIGILL'd (rc=132).
    K1.F21 adds a backpatch-time fallback: on fn_table_lookup miss,
    try the i32-monomorphized mangled name `<target>__i32`.

    The fallback uses a pre-allocated 64-slot scratch region at
    bn_mangle_scratch (slot 170) -- reserved BEFORE the ELF code
    region in install_builtin_names so the backpatch-time write
    doesn't corrupt the code byte stream.

    Test program structure:
      fn id<T>(x: T) -> T { x }
      fn main() -> i32 {
          let _ = id::<i32>(99);  // turbofish: mono produces id__i32
          id(42)                   // bare call: K1.F21 fallback to id__i32
      }

    Pre-K1.F21: the bare `id(42)` call fails fn_table_lookup (only
    `id__i32` is in the table; bare `id` is the skipped template).
    The patch loop emits ud2; main SIGILLs at runtime; rc=132.

    Post-K1.F21: the lookup miss falls through to the mangled
    fallback; finds `id__i32`; resolves the call. Main returns 42.

    Non-i32 T still traps (the fallback always tries __i32 only):
      fn id<T>(x: T) -> T { x }
      fn main() -> i32 {
          let _ = id::<u64>(99);  // mono produces id__u64 only
          id(42)                   // bare call: tries id__i32, MISS -> ud2
      }
    Pre-K1.F21: rc=132 (ud2). Post-K1.F21: rc=132 (still ud2;
    fallback only handles i32). The non-i32 case is a future
    K1.F21b refinement (full type-inference at parse time).
    """
    # Primary probe: bare-call generic-fn resolves to i32 mono.
    rc = _kovc_self_host_compile_and_run(
        "k1f21_bare_call_generic_fn_i32",
        "fn id<T>(x: T) -> T { x } fn main() -> i32 { let _ = id::<i32>(99); id(42) }",
    )
    assert rc == 42, (
        f"K1.F21 generic bare-call fallback: expected exit code 42 "
        f"(`id(42)` resolves to `id__i32` via the K1.F21 backpatch-"
        f"time mangled-name fallback, after `id::<i32>(99)` triggered "
        f"mono to produce the id__i32 concrete clone); got {rc}. "
        f"If rc=132, the fallback didn't fire (or the mangle scratch "
        f"is corrupting the ELF stream). If rc=99, the bare call "
        f"resolved to the turbofish call's clone but returned the "
        f"wrong arg's value."
    )


def test_bootstrap_kovc_k1f22_panic_macro_expansion_self_host():
    """K1.F22 (2026-05-27): the bootstrap's FIRST real macro expansion
    -- `panic!("msg")` rewrites at parse-time to `panic("msg")` AST_CALL,
    using the existing panic builtin codegen (K1.AE: sys_write the
    message, then ud2 trap; K1.AH adds the prefix; K1.AI adds the
    trailing newline).

    Before K1.F22: K1.CB's IDENT!(...) handler treats panic!(...) as a
    no-op-skip that returns AST_INT(0). A program `panic!("oops"); 42`
    returns 42 because the panic never fires.

    After K1.F22: the parser detects the exact `panic!(STR)` shape
    inside K1.CB's is_macro_call branch (id_len=5 + bytes "panic"
    + mac_t2=LPAREN + k+3=TK_STR + k+4=RPAREN), synthesizes an AST_CALL
    with name="panic" (5 bytes pushed to the arena) and a single AST_ARG
    wrapping the AST_STR_LIT. Codegen then dispatches via is_panic_name
    -> the existing panic codegen. The K2 binary emits sys_write then
    ud2; running it gives SIGILL = exit code 132.

    Probe:
      fn main() -> i32 { panic!("oops"); 42 }
        Pre-K1.F22: rc=42 (the no-op + the trailing 42 expression).
        Post-K1.F22: rc=132 (SIGILL from the expanded panic's ud2;
        the `; 42` after never executes).

    The K1.F22 scope is intentionally narrow: only the `panic!(STR)`
    shape with a SINGLE string literal arg. Multi-arg Rust-style
    `panic!("fmt: {}", x)` still hits the K1.CB no-op-skip until a
    more general macro engine lands. Other IDENT!(...) macros
    (println!, vec!, assert_eq!, etc.) also continue to no-op.
    """
    # Primary probe: panic! actually traps.
    rc = _kovc_self_host_compile_and_run(
        "k1f22_panic_macro_traps",
        'fn main() -> i32 { panic!("oops"); 42 }',
    )
    assert rc == 132, (
        f"K1.F22 panic!(\"oops\") expansion: expected exit code 132 "
        f"(SIGILL from the expanded panic's ud2 trap; the `; 42` after "
        f"never executes); got {rc}. If rc=42, the K1.F22 expansion "
        f"didn't fire and panic! reverted to K1.CB's no-op-skip. If "
        f"rc=other, the panic codegen is broken downstream."
    )

    # K1.F22b (2026-05-27): println! now ALSO expands to print_str,
    # so the old K1.F22 regression probe asserting "println! stays
    # no-op" is replaced by the K1.F22b probes below. The rc=42
    # check still passes (print_str returns 0, the trailing `42`
    # gives the final value), but the meaningful side effect
    # (stdout output) is now observable.


def test_bootstrap_kovc_k1f22b_println_macro_expansion_self_host():
    """K1.F22b (2026-05-27): extend the K1.F22 parse-time-rewrite
    pattern to also detect `println!("msg")` and synthesize
    AST_CALL(print_str, str_arg). Routes through the existing
    K1.AK print_str codegen which emits sys_write to stdout and
    returns 0 in eax. Bootstrap-only contract: NO trailing newline
    (print_str doesn't emit one; full Rust println! emit-newline
    is a K1.F22c followup once a print_newline builtin lands).

    The rc-only test doesn't distinguish K1.F22b expansion from
    the K1.CB no-op-skip (both end with `; 42` returning 42, since
    print_str also returns 0). The probes here use the new
    `_kovc_self_host_compile_and_run_with_stdout` helper to check
    that the message ACTUALLY lands on stdout.

      Probe 1: println!("hi"); 42
        Pre-K1.F22b: K1.CB no-op-skip. Stdout empty. rc=42.
        Post-K1.F22b: print_str("hi") emits "hi" to stdout. rc=42.

      Probe 2: println!("a"); println!("b"); 42
        Pre-K1.F22b: Stdout empty.
        Post-K1.F22b: "ab" on stdout (no newlines per the Phase-0
        contract). rc=42.

      Probe 3 (regression): panic!("oops") still SIGILLs (rc=132).
        Verifies K1.F22b doesn't accidentally suppress the K1.F22
        panic! expansion.
    """
    rc1, stdout1 = _kovc_self_host_compile_and_run_with_stdout(
        "k1f22b_println_single",
        'fn main() -> i32 { println!("hi"); 42 }',
    )
    assert rc1 == 42, (
        f"K1.F22b/c println!(\"hi\"); 42: expected exit code 42 "
        f"(print_str_ln returns 0, trailing 42 is the final value); "
        f"got {rc1}. stdout={stdout1!r}."
    )
    # K1.F22c (2026-05-27): println! now emits the trailing newline
    # via the new print_str_ln builtin. stdout = "hi\n".
    assert stdout1 == b"hi\n", (
        f"K1.F22c println! trailing newline probe: expected stdout "
        f"== b'hi\\n' (message + newline via print_str_ln); got "
        f"stdout={stdout1!r}. If stdout==b'hi' (no newline), the "
        f"K1.F22c print_str_ln route regressed to plain print_str."
    )

    rc2, stdout2 = _kovc_self_host_compile_and_run_with_stdout(
        "k1f22b_println_multi",
        'fn main() -> i32 { println!("a"); println!("b"); 42 }',
    )
    assert rc2 == 42, (
        f"K1.F22b/c two-println probe: expected rc=42; got {rc2}. "
        f"stdout={stdout2!r}."
    )
    # K1.F22c: two println!s now produce two newlines.
    assert stdout2 == b"a\nb\n", (
        f"K1.F22c two-println probe: expected stdout == b'a\\nb\\n' "
        f"(each println! emits a trailing newline); got "
        f"stdout={stdout2!r}."
    )

    # Regression: panic! still SIGILLs (K1.F22b didn't break K1.F22).
    rc3 = _kovc_self_host_compile_and_run(
        "k1f22b_panic_still_traps",
        'fn main() -> i32 { panic!("nope"); 42 }',
    )
    assert rc3 == 132, (
        f"K1.F22b regression: expected panic!(\"nope\") to still "
        f"SIGILL with rc=132 (K1.F22 expansion intact); got {rc3}. "
        f"If rc=42, K1.F22 regressed via K1.F22b shadowing."
    )


def test_bootstrap_kovc_k1f22d_eprintln_macro_expansion_self_host():
    """K1.F22d (2026-05-27): stderr variant of K1.F22b/c println!.
    `eprintln!("msg")` parser-side rewrites to AST_CALL(eprint_str_ln,
    str_arg). The new eprint_str_ln builtin (bn_state slot 172, 13
    chars) emits the message + trailing newline via sys_write to fd=2
    (stderr) instead of fd=1 (stdout).

    Probes:
      eprintln!("err"); 42
        Pre-K1.F22d: K1.CB no-op-skip. stderr empty.
        Post-K1.F22d: stderr contains "err\\n", stdout empty.

      Regression: println!("out") still goes to STDOUT (not shadowed by
      the eprintln! arm).
    """
    import os, subprocess
    proj = os.path.dirname(os.path.dirname(os.path.dirname(
        os.path.abspath(__file__))))
    # Direct subprocess to get both stdout AND stderr.
    lexer = open(os.path.join(
        proj, "helixc", "bootstrap", "lexer.hx")).read()
    lexer_no_main = lexer.rsplit(
        "// --------------------------------------------------------------\n// Demo:",
        1,
    )[0]
    parser_body = open(os.path.join(
        proj, "helixc", "bootstrap", "parser.hx")).read()
    kovc = open(os.path.join(
        proj, "helixc", "bootstrap", "kovc.hx")).read()
    kovc_lib = kovc.rsplit(
        "// --------------------------------------------------------------\n// Demo:",
        1,
    )[0]
    name = "k1f22d_eprintln_err"
    in_path = f"/tmp/sh_{name}_in.hx"
    out_path = f"/tmp/sh_{name}_out.bin"
    src = 'fn main() -> i32 { eprintln!("err"); 42 }'
    k1_main = f"""
fn main() -> i32 {{
    let src_start = __arena_len();
    let src_len = read_file_to_arena("{in_path}");
    let tok_base = __arena_len();
    lex(src_start, src_len);
    let ast_root = parse_top(tok_base);
    let total = emit_elf_for_ast_to_path(ast_root);
    let elf_start = __arena_len() - total;
    write_file_to_arena("{out_path}", elf_start, total)
}}
"""
    subprocess.run(
        ["wsl", "-e", "bash", "-c",
         f"rm -f {in_path} {out_path}; printf %s {repr(src)} > {in_path}"],
        check=True, timeout=10,
    )
    compile_and_run(lexer_no_main + parser_body + kovc_lib + k1_main)
    run_k2 = subprocess.run(
        ["wsl", "-e", "bash", "-c",
         f"chmod +x {out_path} && {out_path}"],
        capture_output=True, timeout=10,
    )
    assert run_k2.returncode == 42, (
        f"K1.F22d eprintln!: expected rc=42; got {run_k2.returncode}. "
        f"stdout={run_k2.stdout!r}, stderr={run_k2.stderr!r}."
    )
    assert run_k2.stderr == b"err\n", (
        f"K1.F22d eprintln! stderr probe: expected stderr == b'err\\n' "
        f"(message + newline via eprint_str_ln to fd=2); got "
        f"stderr={run_k2.stderr!r}, stdout={run_k2.stdout!r}."
    )
    assert run_k2.stdout == b"", (
        f"K1.F22d eprintln! stdout probe: expected stdout EMPTY "
        f"(eprintln! should write to stderr only, not stdout); got "
        f"stdout={run_k2.stdout!r}."
    )


def test_bootstrap_kovc_k1f22e_print_macro_expansion_self_host():
    """K1.F22e (2026-05-27): no-newline stdout variant of K1.F22b/c.
    `print!("msg")` parser-side rewrites to AST_CALL(print_str, str_arg).
    Routes through the EXISTING K1.AK print_str builtin (slot 163,
    9 chars) -- no new builtin needed. Contract: message lands on
    stdout EXACTLY as written, with NO trailing newline (the precise
    Rust print!() semantic).

    Probes:
      print!("hi"); 42 -- stdout==b"hi" (NO newline), rc=42.
      print!("a"); print!("b"); 42 -- stdout==b"ab" (concatenated, no
                  newlines anywhere), rc=42.

    Regression: println!("out") still emits trailing newline via
    K1.F22c print_str_ln (verify K1.F22e doesn't shadow K1.F22b/c).
    """
    rc1, stdout1 = _kovc_self_host_compile_and_run_with_stdout(
        "k1f22e_print_single",
        'fn main() -> i32 { print!("hi"); 42 }',
    )
    assert rc1 == 42, (
        f"K1.F22e print!(\"hi\"); 42: expected exit code 42 "
        f"(print_str returns 0, trailing 42 is the final value); "
        f"got {rc1}. stdout={stdout1!r}."
    )
    # K1.F22e contract: NO trailing newline (the distinguishing
    # difference from K1.F22b/c println!). If stdout==b"hi\n", the
    # synthesis routed through print_str_ln instead of plain print_str.
    assert stdout1 == b"hi", (
        f"K1.F22e print! no-newline probe: expected stdout == b'hi' "
        f"(message only, no trailing newline -- the Rust print!() "
        f"contract); got stdout={stdout1!r}. If stdout==b'hi\\n', the "
        f"K1.F22e synthesis incorrectly routed through print_str_ln."
    )

    rc2, stdout2 = _kovc_self_host_compile_and_run_with_stdout(
        "k1f22e_print_multi",
        'fn main() -> i32 { print!("a"); print!("b"); 42 }',
    )
    assert rc2 == 42, (
        f"K1.F22e two-print probe: expected rc=42; got {rc2}. "
        f"stdout={stdout2!r}."
    )
    # Two print!s concatenate with NO newlines anywhere.
    assert stdout2 == b"ab", (
        f"K1.F22e two-print concat probe: expected stdout == b'ab' "
        f"(each print! emits ONLY its message, no newlines); got "
        f"stdout={stdout2!r}."
    )

    # Regression: K1.F22c println! still emits the trailing newline.
    # If K1.F22e accidentally shadowed K1.F22b/c (e.g. by matching
    # IDENT length wrong), println! would lose its newline.
    rc3, stdout3 = _kovc_self_host_compile_and_run_with_stdout(
        "k1f22e_println_regression",
        'fn main() -> i32 { println!("out"); 42 }',
    )
    assert rc3 == 42, (
        f"K1.F22e println! regression probe: expected rc=42; got "
        f"{rc3}. stdout={stdout3!r}."
    )
    assert stdout3 == b"out\n", (
        f"K1.F22e println! regression: expected stdout == b'out\\n' "
        f"(K1.F22c print_str_ln still emits the trailing newline); got "
        f"stdout={stdout3!r}. If stdout==b'out', K1.F22e shadowed the "
        f"println! detection."
    )


