def test_bootstrap_kovc_k1f24f_tile_add_real_loop_known_broken_self_host():
    """K1.F24f (2026-05-27): the real elementwise add loop codegen.

    NOTE [K1.F24j CORRECTION, 2026-05-27 same-day]: this test was
    originally pinned as KNOWN-BROKEN (rc==132 expected) based on
    "3/3 SIGILL with the real elementwise loop." K1.F24i revealed
    that those failures were artifacts of the WSL multi-line helper
    bug (printf %s {repr()} corrupting newlines on disk), NOT a real
    codegen defect. K1.F24j restored the real elementwise loop, and
    the test now passes with rc==13 (3+10=13 since a[0]=3, b[0]=10,
    dst[0]=a[0]+b[0]=13; other dst cells are BSS-zero and __arena_get
    reads dst[0]).

    The flake-tolerant pin {0, 13, 132} is retained so any future
    WSL flake (still possible per K1.F24d) doesn't break the test;
    but the EXPECTED value is now 13. A new K1.F24j strict test
    verifies the multi-element loop body.
    """
    src = (
        'fn main() -> i32 {\n'
        '    let a: i32 = __tile_zeros(2, 2);\n'
        '    let b: i32 = __tile_zeros(2, 2);\n'
        '    let dst: i32 = __tile_zeros(2, 2);\n'
        '    __arena_set(a, 3);\n'
        '    __arena_set(b, 10);\n'
        '    __tile_add(a, b, dst, 4);\n'
        '    __arena_get(dst)\n'
        '}\n'
    )
    results = []
    for run_i in range(3):
        rc = _kovc_self_host_compile_and_run(
            f"k1f24f_real_loop_known_broken_run{run_i}",
            src,
        )
        results.append(rc)
    # Consistent SIGILL across 3 runs = real defect; pin at rc==132.
    # Accept any value (broken or working) so the test passes either way
    # while documenting the broken state.
    assert all(r in [0, 13, 132] for r in results), (
        f"K1.F24f known-broken: unexpected rc values; got {results}. "
        f"Expected: 132 (current broken behavior), 0 (stub fix), or "
        f"13 (real loop ships)."
    )
    # K1.F24j (2026-05-27): with the real loop shipped, rc=13 is now
    # the EXPECTED value (3+10=13 from cell 0). Verify at least one
    # of the 3 runs hits 13.
    assert 13 in results, (
        f"K1.F24j regression: real elementwise loop should produce "
        f"rc=13 in at least one of 3 runs (cell 0 = a[0]+b[0] = "
        f"3+10 = 13); got {results}. WSL may be flaking, or the "
        f"loop codegen regressed."
    )


def test_bootstrap_kovc_k1f24j_tile_add_multi_cell_self_host():
    """K1.F24j (2026-05-27): strict multi-cell verification of the
    real elementwise __tile_add loop shipped in K1.F24j. Tests that
    the loop iterates count times correctly:

    Program:
      a = __tile_zeros(2, 2);  // 4 cells
      b = __tile_zeros(2, 2);
      dst = __tile_zeros(2, 2);
      a[0] = 1; a[1] = 2; a[2] = 3; a[3] = 4;
      b[0] = 10; b[1] = 20; b[2] = 30; b[3] = 40;
      __tile_add(a, b, dst, 4);
      // dst[0]=11, dst[1]=22, dst[2]=33, dst[3]=44
      return dst[0] + dst[1] + dst[2] + dst[3];  // = 11+22+33+44 = 110

    The loop counter / SIB-indexed reads / writes need to all work
    correctly across multiple iterations. A loop bug that only writes
    cell 0 (e.g., the i increment is broken) would give 11. A bug
    that reads/writes wrong cells would give some other wrong sum.

    3-run K1.F24d retry discipline.
    """
    src = (
        'fn main() -> i32 {\n'
        '    let a: i32 = __tile_zeros(2, 2);\n'
        '    let b: i32 = __tile_zeros(2, 2);\n'
        '    let dst: i32 = __tile_zeros(2, 2);\n'
        '    __arena_set(a, 1);\n'
        '    __arena_set(a + 1, 2);\n'
        '    __arena_set(a + 2, 3);\n'
        '    __arena_set(a + 3, 4);\n'
        '    __arena_set(b, 10);\n'
        '    __arena_set(b + 1, 20);\n'
        '    __arena_set(b + 2, 30);\n'
        '    __arena_set(b + 3, 40);\n'
        '    __tile_add(a, b, dst, 4);\n'
        '    __arena_get(dst) + __arena_get(dst + 1) + __arena_get(dst + 2) + __arena_get(dst + 3)\n'
        '}\n'
    )
    results = []
    for run_i in range(3):
        rc = _kovc_self_host_compile_and_run(
            f"k1f24j_multi_cell_run{run_i}",
            src,
        )
        results.append(rc)
    # Expected: 11 + 22 + 33 + 44 = 110.
    assert 110 in results, (
        f"K1.F24j multi-cell: expected rc=110 (sum 11+22+33+44 over "
        f"4 elementwise-added cells) in at least one of 3 runs; "
        f"got {results}. If rc=11 in all 3: only cell 0 is processed "
        f"(loop counter broken). If rc=132 in all 3: SIGILL (codegen "
        f"defect). If mixed: WSL flake (rerun)."
    )


def test_bootstrap_kovc_k1f25_tile_sub_single_cell_self_host():
    """K1.F25 (2026-05-27): __tile_sub(a, b, dst, count) elementwise
    subtraction. Mirrors K1.F24j __tile_add codegen with one byte change:
    the inner `add esi, [rax+rdi*4+4]` (opcode 03) becomes
    `sub esi, [rax+rdi*4+4]` (opcode 2B). Same SIB encoding, same
    4-byte instruction length, so all displacements stay identical.

    Single-cell probe: a[0]=20, b[0]=7, dst[0]=a[0]-b[0]=13. Verifies
    the subtract op-flip lands correctly. 3-run K1.F24d retry discipline.

    Tile ops Phase-0: __tile_zeros + __tile_add + __tile_sub now real.
    Remaining: __tile_mul (slightly different -- imul opcode is 3 bytes,
    so the loop body byte count changes and rel8 displacements shift)
    and __tile_matmul (much more involved -- 2D nested loop with a
    reduction accumulator).
    """
    src = (
        'fn main() -> i32 {\n'
        '    let a: i32 = __tile_zeros(2, 2);\n'
        '    let b: i32 = __tile_zeros(2, 2);\n'
        '    let dst: i32 = __tile_zeros(2, 2);\n'
        '    __arena_set(a, 20);\n'
        '    __arena_set(b, 7);\n'
        '    __tile_sub(a, b, dst, 4);\n'
        '    __arena_get(dst)\n'
        '}\n'
    )
    results = []
    for run_i in range(3):
        rc = _kovc_self_host_compile_and_run(
            f"k1f25_sub_single_run{run_i}",
            src,
        )
        results.append(rc)
    assert 13 in results, (
        f"K1.F25 single-cell: expected rc=13 (20-7) in at least one of "
        f"3 runs; got {results}. If rc=132: SIGILL (regression). If "
        f"all = {results[0]} but != 13: codegen miscompile."
    )


def test_bootstrap_kovc_k1f25_tile_sub_multi_cell_self_host():
    """K1.F25 multi-cell verification.

    NOTE [K1.F26 CORRECTION, 2026-05-27 same-day]: K1.F25's commit
    message claimed an "__arena_get u8-narrowing" defect existed.
    K1.F26 investigation showed this was MISTAKEN. The truncation is
    purely the LINUX KERNEL: `sys_exit(N)` only returns the low 8
    bits of N to the parent process. So when a test program returns
    1050 in eax, the parent sees exit code 1050 & 0xFF = 26. The
    bootstrap and __arena_get are both correct -- the actual value
    in the binary's eax IS 1050, the kernel just truncates the wait4
    status. This is documented in `man 3 exit`: "the least significant
    byte of status... shall be available to a waiting parent process".

    Implication: tests using pytest exit-code-only verification cannot
    distinguish values that differ only in their upper bytes. Tests
    that need to verify > 255 results must use stdout (via __print_int
    or similar) instead of the exit code. The K1.F22b
    `_kovc_self_host_compile_and_run_with_stdout` helper exists for
    exactly this case.

    Program (still valid, all values < 256 individually + sum < 256):
      a=[80, 70, 60, 50], b=[10, 20, 30, 40], count=4
      dst=[70, 50, 30, 10], sum=160 (fits in u8)
    """
    src = (
        'fn main() -> i32 {\n'
        '    let a: i32 = __tile_zeros(2, 2);\n'
        '    let b: i32 = __tile_zeros(2, 2);\n'
        '    let dst: i32 = __tile_zeros(2, 2);\n'
        '    __arena_set(a, 80);\n'
        '    __arena_set(a + 1, 70);\n'
        '    __arena_set(a + 2, 60);\n'
        '    __arena_set(a + 3, 50);\n'
        '    __arena_set(b, 10);\n'
        '    __arena_set(b + 1, 20);\n'
        '    __arena_set(b + 2, 30);\n'
        '    __arena_set(b + 3, 40);\n'
        '    __tile_sub(a, b, dst, 4);\n'
        '    __arena_get(dst) + __arena_get(dst + 1) + __arena_get(dst + 2) + __arena_get(dst + 3)\n'
        '}\n'
    )
    results = []
    for run_i in range(3):
        rc = _kovc_self_host_compile_and_run(
            f"k1f25_sub_multi_run{run_i}",
            src,
        )
        results.append(rc)
    # Expected: 70 + 50 + 30 + 10 = 160 (fits in u8).
    assert 160 in results, (
        f"K1.F25 multi-cell: expected rc=160 (sum 70+50+30+10 over 4 "
        f"elementwise-subtracted cells, all values < 256 to stay within "
        f"the kernel exit-code-u8 truncation envelope) in at least one "
        f"of 3 runs; got {results}."
    )


def test_bootstrap_kovc_k1f26_tile_mul_single_cell_self_host():
    """K1.F26 (2026-05-27): __tile_mul(a, b, dst, count) elementwise
    multiplication. Same loop scaffold as K1.F24j __tile_add but with
    `imul esi, [rax+rdi*4+4]` (opcode 0F AF, 5 bytes) replacing
    `add esi, [rax+rdi*4+4]` (opcode 03, 4 bytes). This shifts the
    loop body from 43 to 44 bytes; jge displacement goes from +39 to
    +40 and jmp displacement from -43 to -44.

    Single-cell: a[0]=4, b[0]=3, dst[0]=12 (3/3 runs).

    Tile ops Phase-0 status after this chunk: 4 of 5 real.
      __tile_zeros, __tile_add, __tile_sub, __tile_mul shipped.
      Remaining: __tile_matmul (2D nested loop with reduction
      accumulator -- structurally different from the elementwise ops).
    """
    src = (
        'fn main() -> i32 {\n'
        '    let a: i32 = __tile_zeros(2, 2);\n'
        '    let b: i32 = __tile_zeros(2, 2);\n'
        '    let dst: i32 = __tile_zeros(2, 2);\n'
        '    __arena_set(a, 4);\n'
        '    __arena_set(b, 3);\n'
        '    __tile_mul(a, b, dst, 4);\n'
        '    __arena_get(dst)\n'
        '}\n'
    )
    results = []
    for run_i in range(3):
        rc = _kovc_self_host_compile_and_run(
            f"k1f26_mul_single_run{run_i}",
            src,
        )
        results.append(rc)
    assert 12 in results, (
        f"K1.F26 single-cell: expected rc=12 (4*3) in at least one of "
        f"3 runs; got {results}."
    )


