        ("ret_vec",          "fn id() -> Vec<i32> { 42 } fn main() -> i32 { id(); 42 }",                        42),
        ("ret_result_two",   "fn id() -> Result<i32, ()> { 42 } fn main() -> i32 { id(); 42 }",                42),
        ("ret_option",       "fn id() -> Option<i32> { 42 } fn main() -> i32 { id(); 42 }",                    42),
