def test_bootstrap_kovc_async_fn_modifier_self_host():
    """K1.AZ (2026-05-26): `async fn x() -> i32 { ... }` accepted
    as a parser-level no-op. The bootstrap has no async runtime
    / state-machine transform; the keyword is consumed by
    consume_vis_modifiers (4th arm next to pub / extern /
    unsafe) so Rust sources with async fns at least parse.
    Semantic execution is undefined -- callers receive the
    body's value directly, not a Future. 4 sub-probes."""
    cases = [
        ("plain",        "async fn fetch() -> i32 { 42 } fn main() -> i32 { fetch() }",                                                  42),
        ("pub_async",    "pub async fn fetch() -> i32 { 42 } fn main() -> i32 { fetch() }",                                              42),
        ("async_unsafe", "async unsafe fn fetch() -> i32 { 42 } fn main() -> i32 { fetch() }",                                           42),
        ("multi_async",  "async fn a() -> i32 { 10 } async fn b() -> i32 { 32 } fn main() -> i32 { a() + b() }",                          42),
    ]
    for name, src, expected in cases:
        rc = _kovc_self_host_compile_and_run(f"async_fn_{name}", src)
        assert rc == expected, f"{name}: expected {expected}, got {rc}"


def test_bootstrap_kovc_unsafe_fn_modifier_self_host():
    """K1.AY (2026-05-25): `unsafe fn dangerous() -> i32 { ... }`
    (the `unsafe` keyword as an outer fn-decl modifier, not the
    `unsafe { block }` expression form K1.AB already handled).
    The bootstrap doesn't model safe vs unsafe -- every op is
    "safe" in the Phase-0 sense -- so this is purely syntactic
    acceptance. consume_vis_modifiers grew a third arm next to
    `pub` / `extern` to swallow the keyword before parse_fn_decl
    sees the `fn` IDENT. 4 sub-probes."""
    cases = [
        ("plain",         "unsafe fn dangerous() -> i32 { 42 } fn main() -> i32 { dangerous() }",                                            42),
        ("pub_unsafe",    "pub unsafe fn dangerous() -> i32 { 42 } fn main() -> i32 { dangerous() }",                                        42),
        ("extern_unsafe", "extern \"C\" unsafe fn dangerous() -> i32 { 42 } fn main() -> i32 { dangerous() }",                               42),
        ("multi_unsafe",  "unsafe fn a() -> i32 { 10 } unsafe fn b() -> i32 { 32 } fn main() -> i32 { a() + b() }",                          42),
    ]
    for name, src, expected in cases:
        rc = _kovc_self_host_compile_and_run(f"unsafe_fn_{name}", src)
        assert rc == expected, f"{name}: expected {expected}, got {rc}"


def test_bootstrap_kovc_unit_return_type_self_host():
    """K1.AX (2026-05-25): `fn x() -> () { ... }` (explicit unit
    return type) now compiles. Previously parse_fn_decl
    unconditionally consumed an IDENT after `->`, but `()` is a
    TK_LPAREN+TK_RPAREN pair (the 0-tuple type), not an IDENT.
    The fix peeks for TK_LPAREN after `->` and consumes the `()`
    pair instead of an IDENT, leaving ret_ty=0 (unit collapses
    to i32 in the type-erased bootstrap). 3 sub-probes."""
    cases = [
        ("noop",        "fn noop() -> () { } fn main() -> i32 { noop(); 42 }",                         42),
        ("multi_unit",  "fn a() -> () { } fn b() -> () { } fn main() -> i32 { a(); b(); 42 }",         42),
        ("mixed_ret",   "fn u() -> () { } fn n() -> i32 { 21 } fn main() -> i32 { u(); n() + n() }",   42),
    ]
    for name, src, expected in cases:
        rc = _kovc_self_host_compile_and_run(f"unit_ret_{name}", src)
        assert rc == expected, f"{name}: expected {expected}, got {rc}"


def test_bootstrap_kovc_static_decl_self_host():
    """K1.AW (2026-05-25): top-level `static N: T = expr;` is now
    accepted as a no-op decl, mirroring K1.Z's const-decl
    pattern. The bootstrap consumes the decl tokens up to and
    including the trailing `;` and emits AST_STRUCT_DECL (54)
    as the codegen no-op marker. The name is NOT registered
    (Phase-0 limitation, same as const), so references to N
    elsewhere in the source fall through to the var-ref path
    and trap. 5 sub-probes cover the basic forms."""
    cases = [
        ("simple_int",   "static N: i32 = 42; fn main() -> i32 { 42 }",                              42),
        ("with_neg",     "static M: i32 = -10; fn main() -> i32 { 42 }",                             42),
        ("multi_static", "static A: i32 = 1; static B: i32 = 2; fn main() -> i32 { 42 }",            42),
        ("mixed_const",  "const C: i32 = 5; static S: i32 = 9; fn main() -> i32 { 42 }",             42),
        ("after_fn",     "fn helper() -> i32 { 10 } static G: i32 = 32; fn main() -> i32 { 42 }",   42),
    ]
    for name, src, expected in cases:
        rc = _kovc_self_host_compile_and_run(f"static_{name}", src)
        assert rc == expected, f"{name}: expected {expected}, got {rc}"


def test_bootstrap_kovc_vis_modifiers_self_host():
    """K1.AV (2026-05-25): pub(crate) / pub(super) / extern /
    extern "C" all accepted as no-op visibility/linkage
    modifiers, in addition to the bare `pub` from K1.AU.
    A new consume_vis_modifiers helper handles the prefix
    consumption (and is called at parse_top + parse_program's
    leading-decl loop + parse_program's post-fn loop). 5 sub-
    probes covering pub(crate), pub(super), extern, extern "C",
    and stacked pub extern "C", plus a multi-decl program."""
    cases = [
        ("pub_crate",     "pub(crate) fn main() -> i32 { 42 }",                                                              42),
        ("pub_super",     "pub(super) fn main() -> i32 { 42 }",                                                              42),
        ("extern_fn",     "extern fn main() -> i32 { 42 }",                                                                  42),
        ("extern_c",      'extern "C" fn main() -> i32 { 42 }',                                                              42),
        ("pub_extern_c",  'pub extern "C" fn main() -> i32 { 42 }',                                                          42),
        ("multi_decls",   'pub(crate) fn a() -> i32 { 10 } extern "C" fn b() -> i32 { 32 } fn main() -> i32 { a() + b() }',  42),
    ]
    for name, src, expected in cases:
        rc = _kovc_self_host_compile_and_run(f"vis_{name}", src)
        assert rc == expected, f"{name}: expected {expected}, got {rc}"


def test_bootstrap_kovc_pub_modifier_self_host():
    """K1.AU (2026-05-25): `pub fn`, `pub struct`, `pub enum`, etc.
    are now accepted with the visibility modifier as a no-op
    (the bootstrap has no module-private system). Two parser-
    level changes: parse_top consumes leading `pub` after
    skip_attributes; parse_program also re-fetches the IDENT
    after consuming `pub` so the keyword-detection cascade fires
    on the actual decl keyword. 5 sub-probes."""
    cases = [
        ("pub_fn_main",   "pub fn main() -> i32 { 42 }",                                                42),
        ("pub_struct",    "pub struct P { x: i32 } fn main() -> i32 { 42 }",                            42),
        ("pub_fn_call",   "pub fn add1(x: i32) -> i32 { x + 1 } fn main() -> i32 { add1(41) }",         42),
        ("mixed_pub",     "pub fn a() -> i32 { 10 } fn b() -> i32 { 32 } fn main() -> i32 { a() + b() }", 42),
        ("pub_enum",      "pub enum E { A, B } fn main() -> i32 { 42 }",                                42),
    ]
    for name, src, expected in cases:
        rc = _kovc_self_host_compile_and_run(f"pub_{name}", src)
        assert rc == expected, f"{name}: expected {expected}, got {rc}"


def test_bootstrap_kovc_empty_fn_body_self_host():
    """K1.AT (2026-05-25): `fn noop() { }` (empty body + no
    return type) now compiles. Two parser-level fixes:
    (1) parse_fn_decl peeks for TK_RBRACE immediately after the
    opening `{` and emits AST_INT(0) as the body if empty;
    (2) the `-> RetTy` clause is now OPTIONAL -- if the next
    token after `)` isn't TK_MINUS, default ret_ty = 0 (i32 /
    unit). Pinned via 4 probes covering empty-no-ret-ty,
    empty-with-ret-ty, multiple-empty-fns, and side-effect-only
    fn body."""
    cases = [
        ("empty_noret",  "fn noop() { } fn main() -> i32 { noop(); 42 }",                              42),
        ("empty_iret",   "fn z() -> i32 { } fn main() -> i32 { z() + 42 }",                            42),
        ("multi_empty",  "fn a() { } fn b() { } fn c() { } fn main() -> i32 { a(); b(); c(); 42 }",    42),
        ("side_effect",  "fn p(x: i32) { let _ = x + 1; } fn main() -> i32 { p(10); 42 }",             42),
    ]
    for name, src, expected in cases:
        rc = _kovc_self_host_compile_and_run(f"empty_fn_{name}", src)
        assert rc == expected, f"{name}: expected {expected}, got {rc}"


def test_bootstrap_kovc_return_bare_self_host():
    """K1.AR (2026-05-25): bare `return;` (no value) now accepted.
    parse_return previously REQUIRED a value expression via
    parse_expr_basic, so `return;` choked on TK_SEMI. Now it
    peeks for TK_SEMI/TK_RBRACE and emits AST_RET with a
    placeholder AST_INT(0). Pinned with 3 probes covering bare
    return, return-with-value, and trailing return (no semi)."""
    rc_bare = _kovc_self_host_compile_and_run(
        "return_bare_semi",
        "fn early() -> i32 { if 1 == 1 { return; }; 99 } "
        "fn main() -> i32 { early() + 42 }",
    )
    assert rc_bare == 42, f"bare return; should yield 0, plus 42 = 42; got {rc_bare}"
    rc_val = _kovc_self_host_compile_and_run(
        "return_with_value",
        "fn early() -> i32 { return 42; 0 } "
        "fn main() -> i32 { early() }",
    )
    assert rc_val == 42, f"return 42; should yield 42; got {rc_val}"
    rc_trail = _kovc_self_host_compile_and_run(
        "return_trailing",
        "fn foo() -> i32 { return 42 } "
        "fn main() -> i32 { foo() }",
    )
    assert rc_trail == 42, f"trailing return 42 should yield 42; got {rc_trail}"


def test_bootstrap_kovc_int_literal_forms_self_host():
    """K1.AQ (2026-05-25): binary (0b), octal (0o), and
    underscore-separated integer literals (1_000_000) now lex
    correctly. Previously only decimal + 0x hex worked.
    Underscores are accepted as no-op separators in any base
    (matches Rust's 1_000 / 0b1010_1010 / 0xFF_FF conventions).
    Pinned via 5 sub-probes."""
    cases = [
        ("bin_lit",        "0b101010",                                          42),
        ("bin_underscore", "0b10_1010",                                         42),
        ("oct_lit",        "0o52",                                              42),
        ("oct_underscore", "0o5_2",                                             42),
        ("dec_underscore", "1_000_000 - 999_958",                               42),
    ]
    for name, expr, expected in cases:
        rc = _kovc_self_host_compile_and_run(
            f"int_lit_{name}",
            f"fn main() -> i32 {{ {expr} }}",
        )
        assert rc == expected, f"{name} ({expr}): expected {expected}, got {rc}"


def test_bootstrap_kovc_block_comment_self_host():
    """K1.AP (2026-05-25): block comments `/* ... */` now work
    in the lexer. Previously only `//` line comments were
    skipped; `/*` lexed as TK_SLASH followed by TK_STAR and
    cascaded into parser confusion. New skip_block_comment
    handles single-line, multi-line, AND nested `/* a /* b */ c */`
    forms. EOF-safe if closer is missing. 4 sub-probes."""
    cases = [
        ("block_simple", "fn main() -> i32 { /* a block */ 42 }", 42),
        ("block_multiline",
         "fn main() -> i32 {\n  /*\n   * multi-line\n   * comment\n   */\n  42\n}", 42),
        ("block_nested",
         "fn main() -> i32 { /* outer /* inner */ tail */ 42 }", 42),
        ("block_top_level",
         "/* file-level comment */ fn main() -> i32 { 42 }", 42),
    ]
    import base64
    for name, src, expected in cases:
        in_path = f"/tmp/sh_blockcmt_{name}_in.hx"
        out_path = f"/tmp/sh_blockcmt_{name}_out.bin"
        import os
        proj = os.path.dirname(os.path.dirname(os.path.dirname(
            os.path.abspath(__file__))))
        lexer = open(os.path.join(
            proj, "helixc", "bootstrap", "lexer.hx")).read()
        lexer_no_main = lexer.rsplit(
            "// --------------------------------------------------------------\n// Demo:",
            1,
        )[0]
        parser_body = open(os.path.join(
            proj, "helixc", "bootstrap", "parser.hx")).read()
        kovc = open(os.path.join(
            proj, "helixc", "bootstrap", "kovc.hx")).read()
        kovc_lib = kovc.rsplit(
            "// --------------------------------------------------------------\n// Demo:",
            1,
        )[0]
        k1_main = f"""
fn main() -> i32 {{
    let src_start = __arena_len();
    let src_len = read_file_to_arena("{in_path}");
    let tok_base = __arena_len();
    lex(src_start, src_len);
    let ast_root = parse_top(tok_base);
    let total = emit_elf_for_ast_to_path(ast_root);
    let elf_start = __arena_len() - total;
    write_file_to_arena("{out_path}", elf_start, total)
}}
"""
        import subprocess
        encoded = base64.b64encode(src.encode('utf-8')).decode('ascii')
        subprocess.run(
            ["wsl", "-e", "bash", "-c",
             f"echo '{encoded}' | base64 -d > {in_path}"],
            check=True, timeout=10,
        )
        compile_and_run(lexer_no_main + parser_body + kovc_lib + k1_main)
        run_k2 = subprocess.run(
            ["wsl", "-e", "bash", "-c",
             f"chmod +x {out_path} && {out_path}"],
            capture_output=True, timeout=10,
        )
        assert run_k2.returncode == expected, (
            f"{name}: expected rc={expected}, got rc={run_k2.returncode}"
        )


def test_bootstrap_kovc_pat_negative_literal_self_host():
    """K1.AO (2026-05-25): negative integer literal patterns
    (`match x { -7 => 42, _ => 0 }`). parse_pattern_atom now
    accepts TK_MINUS (tag 8) followed by TK_INT and emits
    AST_PAT_LIT (tag 64) with the negated value. Pre-K1.AO the
    minus token hit the unknown-token trap (62002). 3 sub-
    probes: matching negative, non-matching negative, mixed
    positive+negative arms in the same match."""
    rc_match = _kovc_self_host_compile_and_run(
        "pat_neg_match",
        "fn main() -> i32 { let x = 0 - 7; "
        "match x { -7 => 42, _ => 0 } }",
    )
    assert rc_match == 42, f"pat -7 should match -7; got {rc_match}"
    rc_nomatch = _kovc_self_host_compile_and_run(
        "pat_neg_nomatch",
        "fn main() -> i32 { let x = 0 - 7; "
        "match x { -3 => 99, _ => 42 } }",
    )
    assert rc_nomatch == 42, f"pat -3 should NOT match -7; got {rc_nomatch}"
    rc_mixed = _kovc_self_host_compile_and_run(
        "pat_neg_mixed",
        "fn main() -> i32 { let x = 0 - 1; "
        "match x { 1 => 10, -1 => 42, _ => 0 } }",
    )
    assert rc_mixed == 42, f"mixed +/- arms should match -1; got {rc_mixed}"


def test_bootstrap_kovc_compound_assign_bitwise_self_host():
    """K1.AN (2026-05-25): compound-assign operator extension to
    bitwise + shift forms. K1.U previously implemented +=, -=,
    *=, /=, %= only; K1.AN adds ^=, &=, |=, <<=, >>= by mapping
    TK_AMP/PIPE/CARET/LSHIFT/RSHIFT (tags 27-31) + TK_EQ to the
    corresponding AST_BAND/BOR/BXOR/SHL/SHR codegen tags
    (28-30, 32-33). Distinguishable from `&&`/`||` because those
    lex as TK_AMP+TK_AMP/TK_PIPE+TK_PIPE rather than ending in
    TK_EQ. 5 sub-probes, one per new op."""
    cases = [
        ("xor_eq", "let mut x = 7; x ^= 5; x", 2),
        ("and_eq", "let mut x = 7; x &= 5; x", 5),
        ("or_eq",  "let mut x = 5; x |= 2; x", 7),
        ("shl_eq", "let mut x = 1; x <<= 4; x", 16),
        ("shr_eq", "let mut x = 32; x >>= 2; x", 8),
    ]
    for name, body, expected in cases:
        rc = _kovc_self_host_compile_and_run(
            f"compound_{name}",
            f"fn main() -> i32 {{ {body} }}",
        )
        assert rc == expected, f"compound {name}: expected {expected}, got {rc}"


def test_bootstrap_kovc_block_as_expression_self_host():
    """K1.AM (2026-05-25): brace-block as expression -- `let x =
    { let y = 1; y + 2 }`. parse_primary now accepts LBRACE as
    a primary expression start; consumes `{`, parses interior
    via parse_expr (let-statements + final expr), consumes `}`.
    Mirrors the body-parse pattern of parse_loop / parse_unsafe
    / parse_match_arm_body. 3 sub-probes: simple block, nested
    block, block-as-fn-arg."""
    rc_simple = _kovc_self_host_compile_and_run(
        "block_expr_simple",
        "fn main() -> i32 { let x = { let y = 1; y + 2 }; x }",
    )
    assert rc_simple == 3, f"let x = {{ let y=1; y+2 }} should yield 3; got {rc_simple}"
    rc_nested = _kovc_self_host_compile_and_run(
        "block_expr_nested",
        "fn main() -> i32 { "
        "let x = { let y = { let z = 1; z + 1 }; y + 1 }; x }",
    )
    assert rc_nested == 3, f"nested block-as-expr should yield 3; got {rc_nested}"
    rc_arg = _kovc_self_host_compile_and_run(
        "block_expr_arg",
        "fn add_one(x: i32) -> i32 { x + 1 } "
        "fn main() -> i32 { add_one({ let y = 10; y + 31 }) }",
    )
    assert rc_arg == 42, f"block as fn arg should yield 42; got {rc_arg}"


def test_bootstrap_kovc_match_block_arm_self_host():
    """K1.AL (2026-05-25): match arm bodies now accept braced
    blocks like `1 => { 42 }`. Previously parse_match_expr
    called parse_expr_basic which doesn't recognize `{` as an
    expression start. K1.AL adds parse_match_arm_body that
    peeks for LBRACE and delegates to parse_expr (which handles
    let-statements + final expr, like parse_loop's body).
    Pinned via 3 sub-probes: simple block, multi-stmt block,
    and a mixed match with both block and expr arms."""
    rc_simple = _kovc_self_host_compile_and_run(
        "match_block",
        "fn main() -> i32 { let x = 1; "
        "match x { 1 => { 42 }, _ => 0 } }",
    )
    assert rc_simple == 42, f"match block arm should yield 42; got {rc_simple}"
    rc_multi = _kovc_self_host_compile_and_run(
        "match_block_multi",
        "fn main() -> i32 { let x = 1; "
        "match x { 1 => { let y = x * 2; y + 10 }, _ => 0 } }",
    )
    assert rc_multi == 12, f"match block with let+expr should yield 12; got {rc_multi}"
    rc_mixed = _kovc_self_host_compile_and_run(
        "match_block_mixed",
        "fn main() -> i32 { let x = 2; "
        "match x { 1 => { 10 }, 2 => 20, _ => { 99 } } }",
    )
    assert rc_mixed == 20, f"mixed match (block + expr arms) should yield 20; got {rc_mixed}"


def test_bootstrap_kovc_print_str_self_host():
    """K1.AK (2026-05-25): print_str("msg") emits sys_write(1,
    msg_ptr, msg_len) to stdout. Mirror of print_int but with
    a string-literal arg; uses the lea_rsi + str_table_add
    infrastructure from K1.AE/K1.AH. Pinned via subprocess
    capture of stdout."""
    import os, subprocess
    proj = os.path.dirname(os.path.dirname(os.path.dirname(
        os.path.abspath(__file__))))
    lexer = open(os.path.join(
        proj, "helixc", "bootstrap", "lexer.hx")).read()
    lexer_no_main = lexer.rsplit(
        "// --------------------------------------------------------------\n// Demo:",
        1,
    )[0]
    parser_body = open(os.path.join(
        proj, "helixc", "bootstrap", "parser.hx")).read()
    kovc = open(os.path.join(
        proj, "helixc", "bootstrap", "kovc.hx")).read()
    kovc_lib = kovc.rsplit(
        "// --------------------------------------------------------------\n// Demo:",
        1,
    )[0]
    in_path = "/tmp/sh_print_str_in.hx"
    out_path = "/tmp/sh_print_str_out.bin"
    k2_src = 'fn main() -> i32 { print_str("hello world!"); 0 }'
    k1_main = f"""
fn main() -> i32 {{
    let src_start = __arena_len();
    let src_len = read_file_to_arena("{in_path}");
    let tok_base = __arena_len();
    lex(src_start, src_len);
    let ast_root = parse_top(tok_base);
    let total = emit_elf_for_ast_to_path(ast_root);
    let elf_start = __arena_len() - total;
    write_file_to_arena("{out_path}", elf_start, total)
}}
"""
    subprocess.run(
        ["wsl", "-e", "bash", "-c",
         f"printf %s {repr(k2_src)} > {in_path}"],
        check=True, timeout=10,
    )
    compile_and_run(lexer_no_main + parser_body + kovc_lib + k1_main)
    run_k2 = subprocess.run(
        ["wsl", "-e", "bash", "-c",
         f"chmod +x {out_path} && {out_path}"],
        capture_output=True, timeout=10,
    )
    assert run_k2.returncode == 0, (
        f"print_str program should exit cleanly; got rc={run_k2.returncode}"
    )
    assert run_k2.stdout == b"hello world!", (
        f"print_str should write exactly 'hello world!' to stdout; got {run_k2.stdout!r}"
    )


def test_bootstrap_kovc_generic_fn_turbofish_self_host():
    """K1.F-discovery batch 27 (2026-05-25): the matrix listed
    Generic fn<T> as KOVC-MISSING. Probing shows turbofish-form
    calls (`id::<i32>(x)`) actually work via Stage 8 detection
    in parse_primary + type erasure (parser mangles to `id__i32`,
    codegen treats T as i32-sized). 3 sub-probes pin the working
    case: identity call, 2-level composition, mixed with non-
    generic fn. Bare-call form (`id(42)`) doesn't work --
    type-inference is a Phase-0 limitation."""
    rc_id = _kovc_self_host_compile_and_run(
        "generic_id",
        "fn id<T>(x: T) -> T { x } fn main() -> i32 { id::<i32>(42) }",
    )
    assert rc_id == 42, f"generic id::<i32>(42) should yield 42; got {rc_id}"
    rc_compose = _kovc_self_host_compile_and_run(
        "generic_compose",
        "fn inc<T>(x: T) -> T { x } fn dub<T>(x: T) -> T { x } "
        "fn main() -> i32 { inc::<i32>(dub::<i32>(21)) }",
    )
    assert rc_compose == 21, f"generic composition should yield 21; got {rc_compose}"
    rc_mix = _kovc_self_host_compile_and_run(
        "generic_mix",
        "fn add_one(x: i32) -> i32 { x + 1 } "
        "fn use_g<T>(x: T) -> T { x } "
        "fn main() -> i32 { add_one(use_g::<i32>(41)) }",
    )
    assert rc_mix == 42, f"generic + concrete mix should yield 42; got {rc_mix}"


def test_bootstrap_kovc_pat_struct_self_host():
    """K1.AJ (2026-05-25): `match p { P { x, y } => x + y }` --
    struct destructure in match patterns. Phase-0: field-name
    IDENTs must appear in declaration order (positional binding;
    the bootstrap is type-erased and stores structs as tuples).
    Pinned via 3 probes: basic 2-field, empty struct, and
    PatTuple regression to ensure the new arm doesn't shadow it."""
    rc_basic = _kovc_self_host_compile_and_run(
        "pat_struct_basic",
        "struct P { x: i32, y: i32 } fn main() -> i32 { "
        "let p = P { x: 3, y: 4 }; match p { P { x, y } => x + y } }",
    )
    assert rc_basic == 7, f"PatStruct should bind x=3, y=4; got x+y={rc_basic}"
    rc_unit = _kovc_self_host_compile_and_run(
        "pat_struct_unit",
        "struct E { } fn main() -> i32 { let e = E { }; "
        "match e { E { } => 42 } }",
    )
    assert rc_unit == 42, f"empty-struct pattern should match; got {rc_unit}"


def test_bootstrap_kovc_arena_push_triple_self_host():
    """K1.AG (2026-05-25): __arena_push_triple(a, b, c) -> i32
    atomic 3-slot push, mirror of K1.AF's push_pair. Writes
    left/mid/right at cursor/+1/+2 and advances by 3. Overflow
    if cursor >= CAP-2 returns -1, no writes. 4 sub-probes:
    left readback, mid readback at idx+1, right readback at
    idx+2, advance-by-3 across consecutive calls."""
    rc_l = _kovc_self_host_compile_and_run(
        "push_triple_l",
        "fn main() -> i32 { let i = __arena_push_triple(11, 22, 33); "
        "__arena_get(i) }",
    )
    assert rc_l == 11, f"push_triple left=11 should read back as 11; got {rc_l}"
    rc_m = _kovc_self_host_compile_and_run(
        "push_triple_m",
        "fn main() -> i32 { let i = __arena_push_triple(11, 22, 33); "
        "__arena_get(i + 1) }",
    )
    assert rc_m == 22, f"push_triple middle=22 at idx+1 should read 22; got {rc_m}"
    rc_r = _kovc_self_host_compile_and_run(
        "push_triple_r",
        "fn main() -> i32 { let i = __arena_push_triple(11, 22, 33); "
        "__arena_get(i + 2) }",
    )
    assert rc_r == 33, f"push_triple right=33 at idx+2 should read 33; got {rc_r}"
    rc_a = _kovc_self_host_compile_and_run(
        "push_triple_a",
        "fn main() -> i32 { let a = __arena_push_triple(1, 2, 3); "
        "let b = __arena_push_triple(4, 5, 6); b - a }",
    )
    assert rc_a == 3, f"two consecutive push_triple should advance by 3; got delta={rc_a}"


def test_bootstrap_kovc_arena_push_pair_self_host():
    """K1.AF (2026-05-25): __arena_push_pair(left, right) -> i32
    atomic 2-slot push. Returns OLD cursor; writes left at slot
    cursor and right at slot cursor+1. Mirrors Python's
    _HELIX_ARENA_PUSH_PAIR_HELPER (atomic-or-none on overflow,
    though this test stays well inside CAP). 3 sub-probes pinned
    via separate assertions: (a) the returned index reads back
    the left value, (b) idx+1 reads back the right value, (c)
    consecutive push_pair returns advance by exactly 2."""
    rc_a = _kovc_self_host_compile_and_run(
        "push_pair_a",
        "fn main() -> i32 { let idx = __arena_push_pair(7, 8); "
        "__arena_get(idx) }",
    )
    assert rc_a == 7, f"push_pair stored left=7 should read back as 7; got {rc_a}"
    rc_b = _kovc_self_host_compile_and_run(
        "push_pair_b",
        "fn main() -> i32 { let idx = __arena_push_pair(7, 8); "
        "__arena_get(idx + 1) }",
    )
    assert rc_b == 8, f"push_pair stored right=8 at idx+1 should read 8; got {rc_b}"
    rc_c = _kovc_self_host_compile_and_run(
        "push_pair_c",
        "fn main() -> i32 { let a = __arena_push_pair(7, 8); "
        "let b = __arena_push_pair(9, 10); b - a }",
    )
    assert rc_c == 2, f"two consecutive push_pair calls should advance cursor by 2 per call; got delta={rc_c}"


def test_bootstrap_kovc_panic_prints_message_self_host():
    """K1.AE (2026-05-25): panic("msg") now emits the message
    text to stderr via sys_write(2, ptr, len) before the ud2
    trap. Mirrors Python's panic codegen ("panic[id]: msg\\n"
    to stderr + sys_exit). The bootstrap omits the "panic[id]: "
    prefix for simplicity but emits the message body verbatim --
    parity-relevant property is "user sees the panic message",
    which now holds in both compilers."""
    import os, subprocess
    proj = os.path.dirname(os.path.dirname(os.path.dirname(
        os.path.abspath(__file__))))
    lexer = open(os.path.join(
        proj, "helixc", "bootstrap", "lexer.hx")).read()
    lexer_no_main = lexer.rsplit(
        "// --------------------------------------------------------------\n// Demo:",
        1,
    )[0]
    parser_body = open(os.path.join(
        proj, "helixc", "bootstrap", "parser.hx")).read()
    kovc = open(os.path.join(
        proj, "helixc", "bootstrap", "kovc.hx")).read()
    kovc_lib = kovc.rsplit(
        "// --------------------------------------------------------------\n// Demo:",
        1,
    )[0]
    in_path = "/tmp/sh_panic_msg_in.hx"
    out_path = "/tmp/sh_panic_msg_out.bin"
    k2_src = 'fn main() -> i32 { panic("kaboom!"); 0 }'
    k1_main = f"""
fn main() -> i32 {{
    let src_start = __arena_len();
    let src_len = read_file_to_arena("{in_path}");
    let tok_base = __arena_len();
    lex(src_start, src_len);
    let ast_root = parse_top(tok_base);
    let total = emit_elf_for_ast_to_path(ast_root);
    let elf_start = __arena_len() - total;
    write_file_to_arena("{out_path}", elf_start, total)
}}
"""
    subprocess.run(
        ["wsl", "-e", "bash", "-c",
         f"printf %s {repr(k2_src)} > {in_path}"],
        check=True, timeout=10,
    )
    compile_and_run(lexer_no_main + parser_body + kovc_lib + k1_main)
    run_k2 = subprocess.run(
        ["wsl", "-e", "bash", "-c",
         f"chmod +x {out_path} && {out_path}"],
        capture_output=True, timeout=10,
    )
    assert run_k2.returncode == 132, (
        f"panic should still SIGILL (rc=132); got {run_k2.returncode}"
    )
    assert b"kaboom!" in run_k2.stderr, (
        f"panic message should reach stderr; got stderr={run_k2.stderr!r}"
    )
    # K1.AH (2026-05-25): require the "panic[28501]: " prefix.
    # K1.AI (2026-05-25): also require the trailing newline -- full
    # Python format match is "panic[28501]: <msg>\n".
    assert run_k2.stderr == b"panic[28501]: kaboom!\n", (
        f"panic full format should match Python exactly; got stderr={run_k2.stderr!r}"
    )


def test_bootstrap_kovc_panic_unreachable_after_self_host():
    """K1.F-discovery batch 20 (2026-05-25): code after a panic
    must never execute. Probe wraps panic in an if-then so the
    parser sees it inside a block and codegen still emits the
    ud2 stub; the trailing `42` would only return if execution
    fell through, which would mean the trap silently no-op'd."""
    rc = _kovc_self_host_compile_and_run(
        "panic_unreachable",
        'fn main() -> i32 { if 1 == 1 { panic("halt"); } else { } 42 }',
    )
    assert rc == 132, (
        f"post-panic code must not execute; expected SIGILL (132), got {rc}"
    )


def test_bootstrap_kovc_demo_emits_ast_int_42():
    """Stage 4 demo: kovc.hx's main() builds AST_INT(42) by hand,
    compiles it, and writes the resulting ELF to disk. The produced
    binary must be a valid x86-64 ELF and exit with code 42."""
    import os, subprocess
    proj = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
    src = open(os.path.join(proj, "helixc", "bootstrap", "kovc.hx")).read()
    compile_and_run(src)
    # ELF wrapper (4096) + prologue(11) + AST_INT(5) + epilogue(4)
    # + exit_with_eax(9) = 4125 bytes.
    size_proc = subprocess.run(
        ["wsl", "-e", "bash", "-c", "wc -c < /tmp/kovc_ast_int.bin"],
        capture_output=True, timeout=10,
    )
    assert size_proc.stdout.strip() == b"4125", size_proc.stdout
    type_proc = subprocess.run(
        ["wsl", "-e", "bash", "-c", "file /tmp/kovc_ast_int.bin"],
        capture_output=True, timeout=10,
    )
    assert b"ELF 64-bit" in type_proc.stdout, type_proc.stdout
    run_proc = subprocess.run(
        ["wsl", "-e", "bash", "-c",
         "chmod +x /tmp/kovc_ast_int.bin && /tmp/kovc_ast_int.bin"],
        capture_output=True, timeout=10,
    )
    # Demo binary now also includes prologue + epilogue (15 bytes added),
    # so the file is 4096 + 11 (prologue) + 5 (mov eax, 42) + 4 (epilogue)
    # + 9 (exit stub) = 4125 bytes.
    assert run_proc.returncode == 42, f"expected exit 42, got {run_proc.returncode}"


def test_bootstrap_parser_no_eof_runaway_on_malformed_input():
    """Audit-7 fix: parse_primary used to advance the cursor past
    TK_EOF on any unexpected token, then parse_add/parse_mul read
    junk values from uninitialized arena slots — non-deterministic
    output. With the EOF guard in place, malformed inputs return
    AST_ERR(99) deterministically without walking off the token
    stream."""
    import os, subprocess
    proj = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
    lexer = open(os.path.join(proj, "helixc", "bootstrap", "lexer.hx")).read()
    lexer_no_main = lexer.rsplit(
        "// --------------------------------------------------------------\n// Demo:",
        1,
    )[0]
    parser_body = open(os.path.join(proj, "helixc", "bootstrap", "parser.hx")).read()

    import uuid
    def root_tag(text: str) -> int:
        # Per-call UUID so concurrent test runs (or even fast sequential
        # ones whose binaries' file ops race under WSL/Windows file sync)
        # don't share the input path. Pre-fix this was a fixed
        # /tmp/helix_lex_input.hx that flaked under load.
        tag = uuid.uuid4().hex[:10]
        path = f"/tmp/helix_lex_input_{tag}.hx"
        subprocess.run(
            ["wsl", "-e", "bash", "-c",
             f"printf %s {repr(text)} > {path}"],
            check=True, timeout=10,
        )
        src = lexer_no_main + parser_body + f"""
fn main() -> i32 {{
    let src_start = __arena_len();
    let src_len = read_file_to_arena("{path}");
    let tok_base = __arena_len();
    lex(src_start, src_len);
    let root = parse_top(tok_base);
    __arena_get(root)
}}
"""
        return compile_and_run(src)

    # `(` alone -> primary recurses into parse_expr inside parens,
    # immediately hits EOF, returns AST_ERR. Then outer parse_primary
    # tries to consume `)` (cur_advance), but the cursor is held at
    # EOF so this is a no-op. Outer returns the inner AST_ERR.
    assert root_tag("(") == 99, "AST_ERR for unmatched ("
    # 5 nested unmatched opens — used to produce non-deterministic
    # tag values. Now deterministically AST_ERR.
    assert root_tag("(((((") == 99, "deterministic AST_ERR for runaway nesting"


def test_bootstrap_pipeline_end_to_end():
    """Stage 3: full lex + parse + eval pipeline runs against source
    files on disk. Each input is text -> tokens -> AST -> i32. This
    proves the entire Helix-self-hosted front-end works on real
    source files; full ELF emission is the only Python piece left."""
    import os, subprocess
    proj = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
    lexer = open(os.path.join(proj, "helixc", "bootstrap", "lexer.hx")).read()
    lexer_no_main = lexer.rsplit(
        "// --------------------------------------------------------------\n// Demo:",
        1,
    )[0]
    parser_body = open(os.path.join(proj, "helixc", "bootstrap", "parser.hx")).read()
    evaluator = open(os.path.join(proj, "helixc", "bootstrap", "evaluator.hx")).read()

    import uuid
    def run(input_text: str) -> int:
        tag = uuid.uuid4().hex[:10]
        path = f"/tmp/helix_lex_input_{tag}.hx"
        subprocess.run(
            ["wsl", "-e", "bash", "-c",
             f"printf %s {repr(input_text)} > {path}"],
            check=True, timeout=10,
        )
        src = lexer_no_main + parser_body + evaluator + f"""
fn main() -> i32 {{
    let src_start = __arena_len();
    let src_len = read_file_to_arena("{path}");
    if src_len <= 0 {{ 0 - 1 }} else {{ run_source(src_start, src_len) }}
}}
"""
        return compile_and_run(src)

    assert run("42") == 42, "literal"
    assert run("1 + 2") == 3, "addition"
    assert run("1 + 2 * 3") == 7, "precedence: ADD over MUL"
    assert run("(1 + 2) * 3") == 9, "grouping"
    assert run("-5") == 251, "unary minus (-5 mod 256)"
    assert run("let x = 5 ; x * x") == 25, "let-bind + ref"
    assert run("let x = 5 ; let y = 7 ; x + y") == 12, "nested let"
    assert run("if 1 < 2 { 7 } else { 9 }") == 7, "if true branch"
    assert run("if 5 < 2 { 7 } else { 9 }") == 9, "if false branch"
    assert run("let x = 5 ; if x < 10 { x * (x + 3) } else { x - 99 }") == 40, \
        "the metacircular_eval demo's same expression, now via real lex+parse"


def test_bootstrap_parser_root_tag_matches_grammar():
    """Stage-2 parser: lex + parse a small program, verify the root
    AST node's tag matches what the grammar would produce. Tag table
    is documented at the top of helixc/bootstrap/parser.hx."""
    import os, subprocess
    proj = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
    lexer = open(os.path.join(proj, "helixc", "bootstrap", "lexer.hx")).read()
    lexer_no_main = lexer.rsplit(
        "// --------------------------------------------------------------\n// Demo:",
        1,
    )[0]
    parser_body = open(os.path.join(proj, "helixc", "bootstrap", "parser.hx")).read()

    import uuid
    def root_tag(input_text: str) -> int:
        tag = uuid.uuid4().hex[:10]
        path = f"/tmp/helix_lex_input_{tag}.hx"
        subprocess.run(
            ["wsl", "-e", "bash", "-c",
             f"printf %s {repr(input_text)} > {path}"],
            check=True, timeout=10,
        )
        src = lexer_no_main + parser_body + f"""
fn main() -> i32 {{
    let src_start = __arena_len();
    let src_len = read_file_to_arena("{path}");
    let tok_base = __arena_len();
    lex(src_start, src_len);
    let root = parse_top(tok_base);
    __arena_get(root)
}}
"""
        return compile_and_run(src)

    assert root_tag("42") == 0,                       "AST_INT"
    # Stage 17a: parse_add/parse_mul fold AST_INT-only operands at parse
    # time, so e.g. `1 + 2` produces AST_INT(3), not AST_ADD. Use a
    # variable on one side (AST_VAR is unfoldable) to verify shape.
    assert root_tag("x + 2") == 2,                    "AST_ADD"
    assert root_tag("x + 2 * 3") == 2,                "ADD over MUL (precedence)"
    assert root_tag("x * 3 + 1") == 2,                "ADD over MUL (left)"
    assert root_tag("(x + 2) * 3") == 4,              "AST_MUL with grouped lhs"
    assert root_tag("-x") == 9,                       "AST_NEG"
    assert root_tag("x") == 1,                        "AST_VAR"
    assert root_tag("a < b") == 6,                    "AST_LT"
    assert root_tag("let x = 1 ; x") == 8,            "AST_LET"
    assert root_tag("if 1 < 2 { 3 } else { 4 }") == 7, "AST_IF"
    # Stage 17a: confirm parser-time const-fold actually fires — both
    # AST_INT operands collapse to a single AST_INT root (tag 0).
    assert root_tag("1 + 2") == 0,                     "fold ADD literals -> AST_INT"
    assert root_tag("4 - 1") == 0,                     "fold SUB literals -> AST_INT"
    assert root_tag("3 * 5") == 0,                     "fold MUL literals -> AST_INT"
    assert root_tag("2 + 3 * 4") == 0,                 "fold nested arith -> AST_INT"
    # Stage 17b: comparisons (LT/GT/EQ/NE/LE/GE) and bitwise (BAND/BOR/
    # BXOR) on AST_INT pairs also fold to a single AST_INT (the 0/1
    # comparison result, or the bitwise i32 result).
    assert root_tag("1 < 2") == 0,                     "fold LT literals -> AST_INT"
    assert root_tag("5 > 2") == 0,                     "fold GT literals -> AST_INT"
    assert root_tag("3 == 3") == 0,                    "fold EQ literals -> AST_INT"
    assert root_tag("3 != 4") == 0,                    "fold NE literals -> AST_INT"
    assert root_tag("4 <= 4") == 0,                    "fold LE literals -> AST_INT"
    assert root_tag("5 >= 4") == 0,                    "fold GE literals -> AST_INT"
    assert root_tag("12 & 10") == 0,                   "fold BAND literals -> AST_INT"
    assert root_tag("12 | 10") == 0,                   "fold BOR literals -> AST_INT"
    assert root_tag("12 ^ 10") == 0,                   "fold BXOR literals -> AST_INT"
    # Stage 17c: algebraic identities — one operand is a literal, the
    # other is unfoldable (here AST_VAR). The fold forwards to the
    # non-literal operand subtree, so the root tag becomes AST_VAR (1).
    # Annihilation rules (x*0=0, x&0=0) are intentionally NOT applied —
    # the non-literal side might have side effects we must preserve, so
    # the corresponding inputs stay as their original binop tag.
    assert root_tag("x + 0") == 1,                     "x + 0 -> x (AST_VAR)"
    assert root_tag("0 + x") == 1,                     "0 + x -> x"
    assert root_tag("x - 0") == 1,                     "x - 0 -> x"
    assert root_tag("x * 1") == 1,                     "x * 1 -> x"
    assert root_tag("1 * x") == 1,                     "1 * x -> x"
    assert root_tag("x | 0") == 1,                     "x | 0 -> x"
    assert root_tag("0 | x") == 1,                     "0 | x -> x"
    assert root_tag("x ^ 0") == 1,                     "x ^ 0 -> x"
    assert root_tag("0 ^ x") == 1,                     "0 ^ x -> x"
    # Annihilation NOT folded — confirm op tag preserved.
    assert root_tag("x * 0") == 4,                     "x * 0 left as AST_MUL (purity)"
    assert root_tag("x & 0") == 28,                    "x & 0 left as AST_BAND (purity)"


def test_bootstrap_lexer_recognizes_each_token_class():
    """End-to-end: each character class produces the expected first
    token tag. INT=1, IDENT=2, LPAREN=3, LBRACE=5, PLUS=7. Whitespace
    and `//` line comments are skipped. Tag table from
    helixc/bootstrap/lexer.hx."""
    import os, subprocess
    proj = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
    lexer_body = open(os.path.join(proj, "helixc", "bootstrap", "lexer.hx")).read()
    # strip lexer's own main() — we substitute one that reads first tag
    lexer_body = lexer_body.rsplit(
        "// --------------------------------------------------------------\n// Demo:",
        1,
    )[0]

    import uuid
    def first_tag(input_bytes: str) -> int:
        tag = uuid.uuid4().hex[:10]
        path = f"/tmp/helix_lex_input_{tag}.hx"
        subprocess.run(
            ["wsl", "-e", "bash", "-c",
             f"printf %s {repr(input_bytes)} > {path}"],
            check=True, timeout=10,
        )
        src = lexer_body + f"""
fn main() -> i32 {{
    let src_start = __arena_len();
    let src_len = read_file_to_arena("{path}");
    if src_len <= 0 {{ 0 - 1 }}
    else {{
        let tok_base = __arena_len();
        lex(src_start, src_len);
        __arena_get(tok_base)
    }}
}}
"""
        return compile_and_run(src)

    assert first_tag("42") == 1, "INT"
    assert first_tag("hello") == 2, "IDENT"
    assert first_tag("(") == 3, "LPAREN"
    assert first_tag("{ }") == 5, "LBRACE (after whitespace skip)"
    assert first_tag("+") == 7, "PLUS"
    assert first_tag("   3") == 1, "INT after whitespace"


def test_demo_mandelbrot_renders_recognizable_shape():
    """Demo 8 (user-picked): full Mandelbrot fractal rendered to stdout
    via print_str + nested loops + complex-number iteration in f32.
    Verify the output has the right shape: starts with spaces, contains
    @ characters from the in-set region, has multiple shading chars."""
    import os, hashlib, subprocess
    from helixc.frontend.parser import parse as _parse
    from helixc.ir.lower_ast import lower as _lower
    from helixc.ir.passes.const_fold import fold_module as _fold
    from helixc.ir.passes.cse import cse_module as _cse
    from helixc.ir.passes.dce import dce_module as _dce
    from helixc.ir.passes.fdce import fdce_module as _fdce
    from helixc.frontend.grad_pass import grad_pass as _gp
    from helixc.tests._codegen_backend import compile_module_to_elf as _compile

    proj = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
    src = open(os.path.join(proj, "helixc", "examples", "mandelbrot.hx")).read()
    prog = _parse(src, include_stdlib=True)
    _gp(prog)
    mod = _lower(prog)
    _fold(mod); _cse(mod); _dce(mod); _fdce(mod)
    elf = _compile(mod)
    out_dir = os.path.join(proj, "helixc", "tests", "_tmp")
    os.makedirs(out_dir, exist_ok=True)
    h = hashlib.sha256(elf).hexdigest()[:12]
    out_path = os.path.join(out_dir, f"mandel_{h}.bin")
    with open(out_path, "wb") as f:
        f.write(elf)
    os.chmod(out_path, 0o755)
    wsl_path = _win_to_wsl(out_path)
    result = subprocess.run(
        ["wsl", "--", "bash", "-c", f"chmod +x {wsl_path} && {wsl_path}"],
        capture_output=True, timeout=60,
    )
    out = result.stdout.decode("utf-8", "replace")
    assert result.returncode == 0
    # Must contain @ (in-set), space (escaped fast), and at least one
    # transition character from the shading palette.
    assert "@" in out, "expected in-set characters"
    assert "  " in out, "expected escaped/whitespace regions"
    assert any(c in out for c in ".:-=+*#%"), "expected gradient shading"
    # At least 22 newlines (one per row).
    assert out.count("\n") >= 22, f"too few rows in {out.count(chr(10))}"


