def test_stage35_wmt_rejects_invalid_tables_and_bounds():
    src = """
    fn main() -> i32 {
        let bad = wmt_new(0 - 1, 2);
        let guard = t1d_new(1);
        ti1d_set(guard, 0, 42);
        let bad_set = wmt_set(bad, 0, 0, 99);
        let bad_predict = wmt_predict(bad, 0, 0);

        let wmt = wmt_new(1, 1);
        let oob_set = wmt_set(wmt, 1, 0, 99);
        let oob_predict = wmt_predict(wmt, 1, 0);
        let invalid_next_set = wmt_set(wmt, 0, 0, 99);
        let invalid_next_predict = wmt_predict(wmt, 0, 0);
        if bad == (0 - 1) {
        if bad_set == (0 - 1) {
        if bad_predict == (0 - 1) {
        if oob_set == (0 - 1) {
        if oob_predict == (0 - 1) {
        if invalid_next_set == (0 - 1) {
        if invalid_next_predict == (0 - 1) {
        if ti1d_get(guard, 0) == 42 { 42 } else { 7 }
        } else { 7 }} else { 7 }} else { 7 }} else { 7 }} else { 7 }} else { 7 }} else { 7 }
    }
    """
    code = compile_and_run(src)
    assert code == 42, f"expected 42, got {code}"


