    src = """
    fn dbl(x: i32) -> i32 { x + x }
    impl I32Util {
        fn doubled(x: i32) -> i32 { dbl(x) }
    }
    fn main() -> i32 {
        I32Util__doubled(21)
    }
    """
    code = compile_and_run(src)
    assert code == 42, f"expected 42, got {code}"


